INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 1, '01', '법적 주체', '법인이 자연인과 구별되는 핵심 특징으로 가장 적절한 것은?', '출생으로 성립한다', '법이 권리·의무 능력을 부여한 인위적 존재다', '세금을 내지 않는다', '해산해도 권리능력이 유지된다', 1, '법인은 설립 등기를 통해 성립하며, 법이 권리·의무의 주체성을 부여한 인위적 존재이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 2, '01', '사업자 형태', '개인사업자와 법인사업자의 비교로 옳은 것은?', '개인사업자는 대표자 급여를 비용 처리할 수 있다', '법인사업자는 무한책임이 원칙이다', '법인사업자는 주식 발행 등 외부 투자 유치가 상대적으로 용이하다', '개인사업자는 법인세를 낸다', 2, '법인사업자는 별도 법인격을 바탕으로 지분 구조 설계와 외부 투자 유치가 상대적으로 유리하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 3, '01', '책임 구조', '유한책임의 의미로 가장 적절한 것은?', '사업채무를 국가가 모두 대신 갚아준다', '출자액 한도 내에서만 책임을 부담한다', '대표이사가 모든 채무를 개인 재산으로 갚는다', '모든 주주는 무한책임을 진다', 1, '유한책임은 투자자가 출자한 금액 범위 내에서만 손실을 부담하는 구조이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 4, '01', '회사 형태', '상법상 회사 형태 중 실제로 가장 보편적으로 사용되는 형태는?', '합명회사', '합자회사', '유한회사', '주식회사', 3, '주식회사가 공개·상장 및 자본조달 측면에서 가장 보편적인 형태이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 5, '01', '주식회사 구조', '주식회사의 최고 의사결정 기관은?', '대표이사', '이사회', '주주총회', '감사', 2, '주주총회가 이사 선임, 정관 변경 등 핵심 사항을 결의하는 최고 의사결정 기관이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 6, '01', '주식 개념', '보통주에 대한 설명으로 가장 적절한 것은?', '의결권이 없다', '배당을 절대 받을 수 없다', '일반적으로 1주 1의결권을 가진다', '시가가 항상 액면가와 같다', 2, '보통주는 의결권이 있고 일반적으로 1주당 1표를 행사한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 7, '01', '소득세', '소득세(개인)와 법인세(법인)의 비교로 옳은 것은?', '소득세 최고세율이 법인세 최고세율보다 낮다', '법인세는 누진구조가 없다', '소득세는 누진세율 구조를 갖고 최고세율이 상대적으로 높다', '법인세는 지방소득세가 없다', 2, '소득세는 6~45%, 법인세는 9~24%로 개인 소득세 누진이 더 가파르다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 8, '01', '부가가치세', '부가가치세(VAT)에 대한 설명으로 옳은 것은?', '세율은 5%가 기본이다', '납부세액은 매출세액-매입세액으로 계산한다', '지방세만 해당된다', '직접세에 해당한다', 1, '부가가치세 기본세율 10%, 납부액은 매출세액에서 매입세액을 차감하는 구조이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 9, '01', '원천징수', '금융소득(이자·배당)의 기본 원천징수 세율은?', '3.3%', '10.0%', '15.4%', '22.0%', 2, '이자·배당소득은 14% + 지방소득세 1.4%로 총 15.4% 원천징수된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 10, '01', '직접세/간접세', '직접세에 해당하는 항목은?', '부가가치세', '주세', '소득세', '담배소비세', 2, '소득세는 납세자와 담세자가 동일한 직접세로 분류된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 11, '01', '간접세', '간접세의 일반적 특징으로 가장 적절한 것은?', '누진세만 가능하다', '납세자와 담세자가 동일하다', '판매자가 납부하지만 소비자가 실질 부담할 수 있다', '지방정부만 부과할 수 있다', 2, '부가가치세처럼 판매자가 신고·납부하나 최종 부담은 소비자에게 전가되는 구조가 대표적이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 12, '01', '조세 분류', '국세에 해당하지 않는 것은?', '소득세', '법인세', '부가가치세', '재산세', 3, '재산세는 지방자치단체가 부과하는 지방세이다. 소득세, 법인세, 부가가치세는 국세이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 13, '01', '소득세', '종합소득세 신고 기간은?', '매년 1월 1일~1월 31일', '매년 3월 1일~3월 31일', '매년 5월 1일~5월 31일', '매년 11월 1일~11월 30일', 2, '종합소득세는 매년 5월 1일부터 5월 31일까지 전년도 소득을 신고·납부한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 14, '01', '부가가치세', '부가가치세 신고·납부는 1년에 몇 회 하는가?', '1회', '2회', '4회', '12회', 1, '부가가치세는 1년에 2회(1기: 1월~6월분을 7월에, 2기: 7월~12월분을 다음해 1월에) 신고·납부한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 15, '01', '원천징수', '원천징수제도의 주요 목적으로 가장 적절한 것은?', '납세자의 편의 제공', '탈세 방지와 세수의 조기 확보', '세무서의 업무 감소', '납세자의 세율 인하', 1, '원천징수는 소득 지급 시 원천에서 미리 세금을 징수하여 탈세를 방지하고 국가가 세수를 조기에 확보하는 목적이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 16, '01', '역진세', '저소득층에게 상대적으로 더 높은 부담을 주는 세금 구조는?', '누진세', '비례세', '역진세', '목적세', 2, '역진세는 소득이 낮을수록 세금 부담 비율이 높아지는 구조이다. 간접세(부가가치세 등)는 저소득층에게 상대적으로 역진적 효과가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 17, '01', '세금 종류', '다음 중 국세이면서 간접세에 해당하는 것은?', '소득세', '법인세', '부가가치세', '재산세', 2, '부가가치세는 국가가 징수하는 국세이며, 사업자가 납부하지만 소비자가 부담하는 간접세이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 18, '01', '소득세 구조', '소득세에서 과세표준이란?', '총 수입금액', '총 수입 - 필요경비', '총 수입 - 필요경비 - 소득공제', '총 수입 - 세액공제', 2, '과세표준은 세율을 적용하는 기준 금액으로, 총수입에서 필요경비와 각종 소득공제를 차감한 금액이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 19, '01', '법인세', '법인이 법인세 신고를 해야 하는 기한은?', '사업연도 종료 후 1개월 이내', '사업연도 종료 후 2개월 이내', '사업연도 종료 후 3개월 이내', '사업연도 종료 후 6개월 이내', 2, '내국법인은 각 사업연도 종료일이 속하는 달의 말일부터 3개월 이내에 법인세를 신고·납부해야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 20, '01', '세금 목적', '특정 목적을 위해 용도를 지정하여 부과하는 세금은?', '보통세', '목적세', '직접세', '간접세', 1, '목적세는 특정 용도에 사용하기 위해 징수되는 세금이다. 교육세, 농어촌특별세 등이 목적세에 해당한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 21, '01', '비례세', '과세표준에 관계없이 일정한 세율을 적용하는 세금은?', '누진세', '역진세', '비례세', '목적세', 2, '비례세는 과세표준이 변해도 세율이 일정한 세금 구조이다. 부가가치세(10%)가 대표적인 비례세이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 22, '01', '소득세', '한국 소득세의 최고세율(45%)이 적용되는 과세표준 기준은?', '5억원 초과', '7억원 초과', '10억원 초과', '15억원 초과', 2, '2021년부터 과세표준 10억원 초과분에는 45%의 최고세율이 적용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 23, '01', '원천징수', '급여소득자의 근로소득 원천징수는 언제 이루어지는가?', '연간 1회 연말정산 시', '급여 지급 시마다', '분기별 1회', '반기별 1회', 1, '근로소득은 매월 급여를 지급할 때마다 간이세액표에 따라 원천징수하고, 다음 해 2월에 연말정산으로 정확한 세액을 확정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 24, '01', '세금 체계', '조세법률주의의 의미로 가장 적절한 것은?', '세금은 법률이 아닌 행정명령으로도 부과 가능하다', '세금의 종류와 세율은 반드시 국회가 제정한 법률로 정해야 한다', '세금 징수는 행정부 재량에 맡긴다', '세금은 지방자치단체가 자율적으로 결정한다', 1, '조세법률주의는 세금의 종류, 세율, 납세의무자 등 세금의 모든 중요 사항은 반드시 국회가 제정한 법률로 규정해야 한다는 원칙이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 25, '01', '법인세', '법인세율이 9%에서 19%로 증가하는 과세표준 구간은?', '1억원 초과', '2억원 초과', '3억원 초과', '5억원 초과', 1, '법인세 과세표준 2억원 이하는 9%, 2억원 초과 200억원 이하는 19%가 적용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 26, '01', '납세 방법', '납세자가 스스로 세액을 계산하여 신고·납부하는 방식은?', '부과납세', '원천징수', '신고납세', '가산세', 2, '신고납세제도는 납세의무자가 과세표준과 세액을 스스로 계산하여 신고·납부하는 방식이다. 소득세·법인세·부가가치세 등이 해당된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 27, '01', '납세 방법', '세무당국이 세액을 결정·통지하면 납세자가 납부하는 방식은?', '신고납세', '원천징수', '가산납세', '부과납세', 3, '부과납세제도는 과세관청이 세액을 결정하여 납세자에게 고지하면 납부하는 방식이다. 재산세·자동차세 등 지방세에서 많이 사용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 28, '01', '세금 납부', '세금을 내야 할 기한을 넘겼을 때 추가로 부과되는 것은?', '가산세', '벌금', '과태료', '이자', 0, '가산세는 세법에서 정한 신고·납부 의무를 이행하지 않은 경우 본세에 추가하여 징수하는 금액이다. 무신고가산세, 납부불성실가산세 등이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 29, '01', '법인세', '법인세의 최고세율(24%)이 적용되는 과세표준은?', '200억원 초과', '500억원 초과', '3,000억원 초과', '1조원 초과', 2, '법인세는 과세표준 3,000억원 초과 구간에 24%의 최고세율이 적용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (1, 30, '01', '원천징수', '프리랜서(사업소득)에 적용되는 원천징수세율은?', '3.3%', '8.8%', '15.4%', '22%', 0, '프리랜서 등 사업소득자에게는 3.3%(소득세 3% + 지방소득세 0.3%)의 원천징수율이 적용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 1, '02', 'CPI', '소비자물가지수(CPI)가 측정하는 것은?', '기업이 구매하는 원자재 가격', '일반 가계가 소비하는 재화·서비스의 평균 가격 변동', '수출품의 평균 가격', '부동산 가격 변동', 1, 'CPI는 도시 가계가 소비하는 대표적 품목 묶음의 가격 변화를 측정하는 지수로 인플레이션의 대표 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 2, '02', 'PPI', '생산자물가지수(PPI)가 선행지표로 활용되는 이유는?', '소비자가격보다 항상 낮기 때문', '기업 원가 상승이 시차를 두고 소비자가격에 전가되기 때문', 'PPI는 GDP와 항상 동일하게 움직이기 때문', '수출입 가격을 직접 반영하기 때문', 1, 'PPI 상승은 기업 원가 증가를 의미하며, 이후 소비자가격(CPI) 상승으로 이어지는 경향이 있어 CPI의 선행지표로 사용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 3, '02', '유가', 'WTI 원유의 거래소와 브렌트유의 거래소가 올바르게 짝지어진 것은?', 'WTI: ICE, 브렌트: NYMEX', 'WTI: NYMEX, 브렌트: ICE', 'WTI: CME, 브렌트: LSE', 'WTI: LME, 브렌트: COMEX', 1, 'WTI(서부텍사스유)는 NYMEX(뉴욕상품거래소)에서, 브렌트유는 ICE(인터콘티넨탈거래소)에서 선물 거래된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 4, '02', '유가', '브렌트유가 국제유가의 기준으로 더 많이 사용되는 이유는?', '생산량이 가장 많기 때문', '미국 정부가 지정한 공식 기준이기 때문', '북해산으로 국제 시장 접근성이 높고 전 세계 거래의 약 70%를 반영하기 때문', 'WTI보다 항상 가격이 낮기 때문', 2, '브렌트유는 북해에서 생산되며 글로벌 원유 거래의 약 70%의 기준가격으로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 5, '02', 'GDP', 'GDP가 2분기 연속 마이너스 성장을 기록할 때 이를 무엇이라 하는가?', '구조적 침체', '기술적 경기침체(Technical Recession)', '디플레이션', '스태그플레이션', 1, '2분기 연속 GDP 성장률이 마이너스를 기록하면 기술적 경기침체(Technical Recession)로 정의된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 6, '02', 'GDP', 'GDP 산출 방법 중 가장 많이 사용되는 지출접근법의 공식은?', 'GDP = C + I + G + (X-M)', 'GDP = C + S + T', 'GDP = W + R + I + P', 'GDP = 총생산 - 중간투입', 0, '지출접근법: GDP = 민간소비(C) + 민간투자(I) + 정부지출(G) + 순수출(X-M)이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 7, '02', '환율', 'USD/KRW 환율이 1,300에서 1,400으로 상승했을 때의 의미는?', '달러 가치 하락, 원화 가치 상승', '달러 가치 상승, 원화 가치 하락(원화 약세)', '물가 하락', '수입물가 하락', 1, 'USD/KRW 환율 상승은 1달러를 사는 데 더 많은 원화가 필요하다는 의미로, 달러 강세·원화 약세를 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 8, '02', '환율', '원화 약세(환율 상승)가 국내 경제에 미치는 영향으로 가장 적절한 것은?', '수출기업 채산성 개선, 수입물가 상승', '수출기업 채산성 악화, 수입물가 하락', '수출·수입 모두 가격 변화 없음', '내수 소비 자동 증가', 0, '원화 약세 시 수출품 가격 경쟁력이 향상되고 수출기업 수익이 개선되지만, 수입물가 상승으로 인플레이션 압력이 커진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 9, '02', '실업률', '미국 비농업부문 고용(NFP)이 발표되는 시기는?', '매월 마지막 금요일', '매월 첫째 금요일', '매 분기 첫째 월요일', '매년 1월 첫째 월요일', 1, 'NFP(Non-Farm Payrolls)는 매월 첫째 금요일에 미국 노동통계국(BLS)이 발표한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 10, '02', '실업률', '실업률 통계에서 "실업자"로 분류되기 위한 조건은?', '일을 하고 있지 않은 모든 성인', '일을 원하지 않는 사람', '일할 의사가 있고 구직활동을 하고 있지만 취업하지 못한 사람', '학생이거나 군복무 중인 사람', 2, '실업자는 일할 능력과 의사가 있으며 구직활동을 했음에도 취업하지 못한 사람으로 정의된다. 구직을 포기한 사람은 비경제활동인구로 분류된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 11, '02', 'FRED', '미국 연방준비은행 경제데이터 플랫폼 FRED를 운영하는 기관은?', '미국 재무부', '뉴욕 연방준비은행', '세인트루이스 연방준비은행', 'IMF', 2, 'FRED(Federal Reserve Economic Data)는 세인트루이스 연방준비은행이 운영하는 경제 데이터 플랫폼이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 12, '02', 'CPI', 'CPI에서 음식과 에너지를 제외한 지수를 무엇이라 하는가?', '생산자물가지수', '근원 CPI(Core CPI)', 'PCE 디플레이터', 'GDP 디플레이터', 1, '근원 CPI는 변동성이 큰 음식과 에너지를 제외한 물가지수로 기저 인플레이션 추세를 파악하는 데 사용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 13, '02', '유가', '유가 상승이 인플레이션에 미치는 경로로 가장 적절한 것은?', '유가 상승 → 운송·에너지 비용 증가 → 전반적 물가 상승', '유가 상승 → 소비 증가 → 물가 하락', '유가 상승 → 기업 이익 증가 → 임금 하락', '유가 상승은 물가에 직접 영향 없음', 0, '유가 상승은 운송·에너지 비용 증가를 통해 생산비 전반에 영향을 미치고, 이는 소비자물가 상승(인플레이션)으로 이어진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 14, '02', 'GDP', 'GDP와 GNP의 차이에 대한 설명으로 올바른 것은?', 'GDP는 국민 기준, GNP는 국내 영토 기준이다', 'GDP는 국내 영토 기준, GNP는 자국민 기준이다', 'GDP와 GNP는 항상 동일하다', 'GNP는 현재 사용되지 않는 개념이다', 1, 'GDP(국내총생산)는 국내 영토에서 생산된 부가가치, GNP(국민총생산)는 자국민이 어디서든 생산한 부가가치를 측정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 15, '02', '인플레이션', '인플레이션이 높아질 때 중앙은행이 일반적으로 취하는 정책은?', '기준금리 인하', '기준금리 인상', '국채 매입(양적완화)', '지급준비율 인하', 1, '인플레이션 억제를 위해 중앙은행은 기준금리를 인상하여 대출 비용을 높이고 소비·투자를 억제한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 16, '02', '환율', '경상수지 흑자가 지속될 때 환율(USD/KRW)에 미치는 일반적 영향은?', '원화 약세(환율 상승)', '환율 변동 없음', '원화 강세(환율 하락)', '달러 강세', 2, '경상수지 흑자는 외화 공급 증가를 의미하여 원화 수요가 상대적으로 증가, 원화 강세(환율 하락) 압력으로 작용한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 17, '02', 'PPI', 'PPI와 CPI의 관계에 대한 설명으로 가장 적절한 것은?', 'PPI는 CPI보다 항상 높다', 'PPI 상승이 시차를 두고 CPI 상승으로 이어지는 경향이 있다', 'CPI가 PPI를 선행한다', 'PPI와 CPI는 무관하다', 1, 'PPI는 생산 단계의 물가를 측정하므로 기업 원가 상승이 최종 소비자가격에 반영되기까지 시차가 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 18, '02', 'GDP', '실질 GDP와 명목 GDP의 차이는?', '실질 GDP는 특정 기준 연도 물가로 조정된 GDP이다', '명목 GDP가 항상 실질 GDP보다 작다', '실질 GDP는 해외 생산을 포함한다', '명목 GDP는 인플레이션 효과를 제거한 수치이다', 0, '실질 GDP는 물가 변동 효과를 제거하여 실제 생산량 변화를 측정하고, 명목 GDP는 현재 가격으로 계산된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 19, '02', '실업률', '경기 침체기에 실업률이 높아지는 주요 이유는?', '노동자들이 자발적으로 일을 그만두기 때문', '기업이 비용 절감을 위해 고용을 줄이기 때문', '정부가 고용을 제한하기 때문', '최저임금이 자동으로 상승하기 때문', 1, '경기 침체 시 기업 매출과 이익이 감소하여 비용 절감 목적으로 감원(layoff)을 단행하므로 실업률이 상승한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 20, '02', 'CPI', 'CPI 상승률이 중앙은행의 목표(예: 2%)를 지속적으로 하회할 때 우려되는 현상은?', '하이퍼인플레이션', '디플레이션 또는 저인플레이션으로 인한 경기 위축', '환율 급등', '주식시장 버블', 1, 'CPI가 지속적으로 목표를 하회하면 물가 하락 기대가 소비 이연을 유발하고 경기 위축(디플레이션 위험)이 생길 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 21, '02', '유가', 'OPEC+ 감산 결정이 유가에 미치는 일반적 영향은?', '공급 감소로 유가 상승 압력', '공급 증가로 유가 하락 압력', '유가에 영향 없음', '달러 강세로 유가 하락', 0, 'OPEC+ 산유국들이 감산을 결정하면 글로벌 원유 공급이 줄어 수요-공급 균형 변화로 유가 상승 압력이 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 22, '02', '거시경제', '스태그플레이션(stagflation)을 가장 잘 설명하는 것은?', '높은 성장과 낮은 물가', '낮은 성장(경기침체)과 높은 인플레이션의 동시 발생', '높은 성장과 높은 물가', '낮은 성장과 낮은 물가', 1, '스태그플레이션은 경기 침체(stagnation)와 인플레이션(inflation)이 동시에 발생하는 상황으로 1970년대 오일쇼크 때 주목받았다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 23, '02', '환율', '달러 인덱스(DXY)가 상승할 때 일반적으로 달러 대비 신흥국 통화에 나타나는 현상은?', '신흥국 통화 강세', '신흥국 통화 약세', '신흥국 통화 변동 없음', '선진국 통화도 동반 강세', 1, '달러 인덱스 상승은 달러 강세를 의미하며, 이 경우 신흥국 통화는 상대적으로 약세를 보이는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 24, '02', 'GDP', 'GDP 성장률이 투자자에게 중요한 이유로 가장 적절한 것은?', '세율 결정에 직접 영향을 주기 때문', '기업 이익과 시장 전반의 성장 방향을 반영하기 때문', '환율을 직접 결정하기 때문', '중앙은행 총재 임기와 관련되기 때문', 1, 'GDP 성장률은 경제 전반의 활력을 나타내며 기업 매출·이익 성장과 밀접하게 연관되어 주식시장 방향성에 영향을 준다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 25, '02', 'CPI', '전년 동월 대비 CPI가 5% 상승했다는 의미는?', '이번 달 물가가 지난달보다 5% 올랐다', '1년 전 같은 달보다 물가가 평균 5% 올랐다', '5년간 물가가 5% 올랐다', '핵심 물가만 5% 올랐다', 1, 'YoY(전년 동월 대비) CPI 5% 상승은 1년 전 같은 달과 비교하여 소비자물가가 평균 5% 높아졌음을 의미한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 26, '02', '실업률', '자연실업률(natural rate of unemployment)에 포함되지 않는 것은?', '마찰적 실업', '구조적 실업', '경기적 실업', '자발적 실업', 2, '자연실업률은 경기 변동과 무관한 마찰적·구조적 실업을 포함한다. 경기 침체로 인한 경기적 실업은 자연실업률에 포함되지 않는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 27, '02', '유가', '원유 가격 하락이 항공·운송업에 미치는 직접적 영향은?', '연료비 증가로 비용 상승', '연료비 감소로 수익성 개선', '매출 직접 감소', '고용 의무적 증가', 1, '원유 가격 하락은 제트유·경유 등 연료비 감소로 이어져 항공·운송업체의 원가 절감 및 수익성 개선에 직접 기여한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 28, '02', '거시경제', '미국 연방공개시장위원회(FOMC)의 주요 역할은?', '환율 직접 결정', '기준금리(연방기금금리) 결정', '국채 발행 결정', '주식시장 규제', 1, 'FOMC는 미국 연방준비제도의 통화정책 결정 기구로 기준금리(연방기금금리 목표범위)를 결정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 29, '02', 'PPI', 'PPI를 구성하는 주요 항목이 아닌 것은?', '원자재 가격', '반제품·중간재 가격', '완제품 출하 가격', '소매점 판매 가격', 3, 'PPI는 생산자 단계에서의 가격을 측정하며 원자재, 중간재, 완제품(출하가격) 등을 포함한다. 소매점 판매가격은 CPI 영역이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (2, 30, '02', 'GDP', '경제성장률이 잠재성장률을 초과할 때 일반적으로 나타나는 현상은?', '디플레이션', '인플레이션 압력 증가', '실업률 자동 상승', '수출 감소', 1, '실제 성장률이 잠재성장률(공급 능력)을 초과하면 수요 초과로 물가 상승(인플레이션) 압력이 높아진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 1, '03', '경기사이클', '경기사이클 4단계를 순서대로 나열한 것은?', '회복→확장→후퇴→수축', '확장→회복→수축→후퇴', '수축→후퇴→확장→회복', '후퇴→수축→회복→확장', 0, '경기사이클은 회복(recovery) → 확장(expansion) → 후퇴(slowdown) → 수축(contraction) 순으로 순환한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 2, '03', '선행지표', '다음 중 경기 선행지표에 해당하는 것은?', '실업률', '주식시장 지수', 'GDP 성장률', '소비자물가지수', 1, '주가지수는 기업의 미래 이익 기대를 반영하므로 경기 선행지표로 분류된다. 실업률과 GDP는 동행 또는 후행지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 3, '03', '후행지표', '다음 중 경기 후행지표에 해당하는 것은?', '건축 허가 건수', '장단기 금리차', '실업률', '제조업 신규 수주', 2, '실업률은 기업이 경기 악화 후 감원을 결정하는 데 시간이 걸리므로 경기 후퇴 이후에 반응하는 후행지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 4, '03', '통화량', 'M1 통화량에 포함되지 않는 것은?', '현금', '요구불예금', '수시입출금식 예금', '2년 이상 정기예금', 3, 'M1은 현금과 즉시 인출 가능한 요구불예금, 수시입출금 예금 등 협의의 통화를 포함한다. 2년 이상 정기예금은 M2에 포함된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 5, '03', '통화량', 'M2는 M1에 어떤 항목을 추가한 것인가?', '해외 보유 달러', '2년 미만 정기예금, MMF 등 준통화', '회사채', '주식', 1, 'M2는 M1에 2년 미만 정기예금, MMF, 금융채 등 단기 저축성 예금과 단기 금융상품을 더한 광의의 통화지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 6, '03', 'QE', '양적완화(QE, Quantitative Easing)의 핵심 메커니즘은?', '기준금리를 급격히 인상한다', '중앙은행이 국채 등 자산을 매입하여 시중 유동성을 공급한다', '정부가 세금을 인하하여 소비를 촉진한다', '시중은행이 대출 금리를 자율적으로 낮춘다', 1, 'QE는 중앙은행이 국채·MBS 등을 매입하여 본원통화를 늘리고 시중에 유동성을 직접 공급하는 비전통적 통화정책이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 7, '03', 'QT', '양적긴축(QT, Quantitative Tightening)이란?', '중앙은행이 보유 자산을 매각하거나 만기 상환 후 재투자하지 않아 유동성을 흡수하는 정책', '정부가 재정지출을 늘리는 정책', '기준금리를 제로로 낮추는 정책', '시중은행 지급준비율을 낮추는 정책', 0, 'QT는 QE의 반대로 중앙은행이 보유 채권을 매각하거나 만기 도래분을 재투자하지 않아 시중 유동성을 흡수한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 8, '03', '섹터로테이션', '경기 확장 초기에 상대적으로 강세를 보이는 섹터는?', '유틸리티', '헬스케어', '경기소비재·금융', '통신', 2, '경기 확장 초기에는 소비가 늘고 금리 상승 기대로 경기소비재와 금융 섹터가 상대적으로 좋은 성과를 내는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 9, '03', '섹터로테이션', '경기 수축 국면에서 상대적으로 방어적인 섹터는?', '에너지', '금융', '유틸리티·헬스케어', '소재', 2, '경기 침체기에는 전기·수도 등 생활 필수재를 공급하는 유틸리티와 의료 수요가 경기에 덜 민감한 헬스케어가 방어적으로 작용한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 10, '03', '선행지표', '장단기 금리 역전(yield curve inversion)이 경기침체 선행지표로 여겨지는 이유는?', '장기채 금리가 낮아지면 은행 대출이 증가하기 때문', '단기금리가 장기금리를 초과하면 은행 수익성 악화와 신용 위축이 발생하기 때문', '역전은 물가 하락만을 의미하기 때문', '역전은 수출 증가 신호이기 때문', 1, '장단기 금리 역전 시 은행의 예대마진이 축소되어 대출이 줄고, 미래 성장에 대한 비관적 기대가 반영되어 경기침체 선행지표로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 11, '03', '경기사이클', '경기 후퇴기(slowdown)의 특징으로 가장 적절한 것은?', '성장률이 가속화된다', '고용이 급증한다', '성장률이 둔화되고 기업 재고가 쌓이기 시작한다', '소비가 정점을 찍고 빠르게 증가한다', 2, '경기 후퇴기는 성장률이 둔화되고 기업 재고가 증가하며 투자·고용이 감소하기 시작하는 단계이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 12, '03', '통화량', 'M0(본원통화)의 구성 요소는?', '은행 대출 전체', '시중은행 보유 중앙은행 지급준비금 + 유통 중인 현금', '주식시장 시가총액', '정부 국채 발행액', 1, 'M0(본원통화)은 중앙은행이 발행한 현금(시중 유통) + 시중은행이 중앙은행에 예치한 지급준비금으로 구성된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 13, '03', 'QE', 'QE 시행 시 자산 시장에 나타나는 일반적 현상은?', '주식·채권 가격 하락', '주식·채권 가격 상승 (유동성 효과)', '부동산 가격만 상승', '모든 자산 가격 하락', 1, 'QE로 유동성이 증가하면 채권 수익률이 하락(채권 가격 상승)하고 위험자산으로 자금이 이동하여 주식 가격도 상승하는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 14, '03', '경기지표', '동행지표에 해당하는 것은?', '장단기 금리차', '건축 허가', '산업생산지수', '기업 대출 잔액', 2, '산업생산지수는 현재 생산 활동을 직접 반영하므로 경기 동행지표이다. 장단기 금리차와 건축 허가는 선행지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 15, '03', '통화정책', '중앙은행이 기준금리를 인상할 때 예상되는 경제적 효과는?', '기업 투자 증가, 소비 증가', '대출 비용 증가, 소비·투자 억제, 인플레이션 완화', '통화량 자동 증가', '환율 하락(자국통화 약세)', 1, '금리 인상은 대출 비용을 높여 소비·투자를 줄이고 통화량 증가를 억제하여 인플레이션을 낮추는 효과를 가진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 16, '03', '경기사이클', '경기국면을 점수화하는 방식에서 0~6점 범위를 사용할 때 점수가 높을수록 의미하는 것은?', '경기 수축 국면', '경기 확장 국면', '물가 하락 국면', '금리 상승 국면', 1, '경기국면 점수화는 여러 경기지표의 상태를 합산하여 점수가 높을수록 경기 확장 국면, 낮을수록 수축 국면임을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 17, '03', 'QT', 'QT(양적긴축)가 시장에 미치는 일반적 영향은?', '채권 공급 증가 → 채권 가격 하락 → 금리 상승', '채권 공급 감소 → 채권 가격 상승 → 금리 하락', '주식 가격 자동 상승', '환율 하락', 0, 'QT로 중앙은행이 채권을 매각하면 채권 공급이 늘어 채권 가격이 하락하고 시장 금리가 상승하는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 18, '03', '선행지표', '소비자신뢰지수(Consumer Confidence Index)가 선행지표인 이유는?', '과거 소비를 집계하기 때문', '향후 소비 의향을 반영하므로 미래 소비 방향을 예측하는 데 유용하기 때문', '기업 생산을 직접 측정하기 때문', '정부 지출을 반영하기 때문', 1, '소비자신뢰지수는 가계의 경제 상황에 대한 기대와 소비 계획을 반영하므로 향후 소비 지출의 선행지표로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 19, '03', '통화량', '통화 승수(money multiplier)란?', '중앙은행 기준금리와 시장금리의 비율', '본원통화 1단위가 신용창조를 통해 늘어나는 통화량 배수', '주식 시장의 PER', '정부 재정승수', 1, '통화 승수는 시중은행의 신용창조 과정을 통해 본원통화 1원이 최종적으로 몇 배의 통화량을 만들어내는지를 나타내는 개념이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 20, '03', '경기사이클', '경기 수축(침체)기에 투자자가 일반적으로 취하는 전략은?', '경기민감주 비중 확대', '고위험 성장주 집중 투자', '방어주·채권·현금 비중 확대', '레버리지 확대', 2, '경기 수축기에는 수익 하락 리스크가 크므로 변동성이 낮은 방어주(유틸리티, 헬스케어), 채권, 현금 비중을 높이는 보수적 전략이 유효하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 21, '03', 'QE', '미국 연준이 2008년 금융위기 이후 QE를 시행한 주된 목적은?', '환율 절하', '기준금리가 이미 0%에 가까워 추가 금리 인하가 불가하여 유동성 직접 공급', '국채 이자비용 증가', '재정적자 축소', 1, '2008년 위기 후 연준은 기준금리를 거의 0%까지 낮췄음에도 경기 회복이 부진하여 국채·MBS 매입(QE)으로 유동성을 추가 공급했다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 22, '03', '경기지표', '제조업 구매관리자지수(PMI)에서 50 이상의 의미는?', '경기 수축', '경기 확장', '물가 상승', '실업률 증가', 1, 'PMI 50은 기준선으로 50 이상이면 제조업 경기 확장, 50 미만이면 수축을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 23, '03', '통화량', 'M2 증가율이 높을 때 인플레이션 위험이 커지는 이유는?', '통화량 증가 → 화폐가치 하락 → 물가 상승', '통화량 증가 → 금리 자동 상승 → 소비 감소', '통화량은 물가와 무관하다', '통화량 증가 → 수출 감소', 0, '통화량이 실물 생산량보다 빠르게 증가하면 화폐 가치가 상대적으로 하락하여 물가 상승(인플레이션) 압력이 발생한다(화폐수량설).');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 24, '03', '섹터로테이션', '경기 회복 초기에 가장 먼저 반응하는 섹터는?', '유틸리티', '소재·에너지', '통신', '헬스케어', 1, '경기 회복 초기에는 원자재 수요 증가 기대로 소재와 에너지 섹터가 먼저 반응하는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 25, '03', '경기사이클', '경기 확장기에 일반적으로 나타나는 현상이 아닌 것은?', '실업률 하락', '기업 투자 증가', '소비자 지출 증가', '기업 도산 급증', 3, '경기 확장기에는 고용·소비·투자가 모두 증가한다. 기업 도산 급증은 경기 수축기의 특징이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 26, '03', '선행지표', '주택 착공 건수가 경기 선행지표인 이유는?', '주택 완공 후에 집계되기 때문', '착공은 건설 투자 계획을 반영하므로 향후 경제활동 증가를 시사하기 때문', '주택 가격과 항상 반비례하기 때문', '중앙은행이 직접 관리하기 때문', 1, '주택 착공은 건설·자재·금융 등 연관 산업 전반의 활동을 유발하므로 향후 경제 활동의 선행지표로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 27, '03', '통화정책', '지급준비율(reserve ratio) 인하의 효과는?', '통화량 감소', '은행의 대출 여력 감소', '시중 유동성 확대', '기준금리 자동 인상', 2, '지급준비율 인하 시 은행이 대출로 운용할 수 있는 자금이 늘어나 신용 창조를 통해 시중 통화량이 확대된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 28, '03', '경기사이클', '경기사이클에서 "트로프(trough)"란?', '경기의 최고점', '경기의 최저점', '경기 확장 중반', '경기 후퇴 시작점', 1, '트로프(trough)는 경기사이클에서 경기가 가장 낮은 바닥 지점으로, 이후부터 회복 국면이 시작된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 29, '03', 'QE/QT', 'QE와 QT가 주식시장에 미치는 방향이 올바르게 짝지어진 것은?', 'QE: 하락, QT: 상승', 'QE: 상승, QT: 하락', 'QE: 하락, QT: 하락', 'QE: 상승, QT: 상승', 1, 'QE는 유동성 공급으로 위험자산(주식) 가격 상승을 지지하고, QT는 유동성 흡수로 주식시장에 하방 압력을 주는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (3, 30, '03', '경기지표', '다음 중 경기후행지표로 분류되는 것은?', '장단기 금리 스프레드', '제조업 신규 수주', '소비자물가지수(CPI)', 'M2 증가율', 2, 'CPI는 경제활동의 결과가 물가에 반영되기까지 시차가 있어 경기후행지표로 분류되는 경우가 많다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 1, '04', 'Porter 5 Forces', 'Porter의 5가지 경쟁요인(Five Forces)에 포함되지 않는 것은?', '신규 진입자 위협', '대체재 위협', '정부 규제 강도', '구매자 교섭력', 2, 'Porter 5 Forces는 신규 진입자, 대체재, 구매자 교섭력, 공급자 교섭력, 기존 경쟁자 간 경쟁강도로 구성된다. 정부 규제는 직접 포함되지 않는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 2, '04', 'Porter 5 Forces', '구매자 교섭력이 강해지는 조건은?', '구매자 수가 많고 개별 구매량이 적을 때', '구매자 수가 적고 대량 구매할 때', '전환비용이 높을 때', '공급자가 독점일 때', 1, '구매자 교섭력은 구매자 수가 적고 대량 구매 시, 전환비용이 낮을수록 강해진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 3, '04', 'Porter 5 Forces', '진입장벽이 높을 때 신규 진입자 위협은?', '매우 높다', '낮아진다', '변화 없다', '대체재 위협과 동일해진다', 1, '진입장벽(규모의 경제, 특허, 브랜드, 초기 자본 등)이 높으면 신규 경쟁자가 시장에 들어오기 어려워 기존 기업의 경쟁 위협이 낮아진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 4, '04', 'SWOT', 'SWOT 분석에서 "O"가 의미하는 것은?', '운영 효율성(Operational)', '기회(Opportunity)', '조직 구조(Organization)', '외부 위협(Outside threat)', 1, 'SWOT는 Strengths(강점), Weaknesses(약점), Opportunities(기회), Threats(위협)의 약자이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 5, '04', 'SWOT', 'SWOT 분석에서 내부 요인에 해당하는 것은?', '경쟁사의 신제품 출시', '정부 규제 완화', '자사의 기술력과 브랜드 가치', '글로벌 수요 증가', 2, 'SWOT에서 강점(S)과 약점(W)은 기업 내부 요인이고, 기회(O)와 위협(T)은 외부 환경 요인이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 6, '04', 'PEST', 'PEST 분석의 4가지 요소가 올바르게 짝지어진 것은?', '정치, 경제, 사회, 기술', '생산, 효율, 시스템, 기술', '가격, 환경, 서비스, 기술', '정치, 에너지, 시스템, 기업', 0, 'PEST는 Political(정치), Economic(경제), Social(사회문화), Technological(기술) 환경을 분석하는 프레임워크이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 7, '04', 'PEST', 'PEST 분석에서 고령화 트렌드는 어느 요소에 해당하는가?', '정치(Political)', '경제(Economic)', '사회(Social)', '기술(Technological)', 2, '고령화는 인구구조 변화로 사회문화적 환경(Social) 요소에 해당한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 8, '04', '산업수명주기', '산업수명주기 4단계를 순서대로 나열한 것은?', '성장→도입→성숙→쇠퇴', '도입→성장→성숙→쇠퇴', '성숙→성장→도입→쇠퇴', '도입→성숙→성장→쇠퇴', 1, '산업수명주기는 도입(introduction) → 성장(growth) → 성숙(maturity) → 쇠퇴(decline) 4단계로 진행된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 9, '04', '산업수명주기', '성장기 산업의 특징으로 가장 적절한 것은?', '시장 포화, 경쟁 치열, 저마진', '수요 급성장, 신규 진입자 증가, 고마진 가능', '매출 감소, 기업 구조조정', '표준화된 제품, 가격 경쟁 위주', 1, '성장기에는 수요가 빠르게 늘고 시장이 확대되어 신규 진입자가 몰리며, 초기 선점 기업은 높은 마진을 누릴 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 10, '04', '산업수명주기', '성숙기 산업에서 기업이 주로 사용하는 전략은?', '대규모 R&D 투자', '시장 점유율 확대를 위한 공격적 성장', '비용 절감과 효율화, 현금흐름 극대화', '신시장 개척을 위한 막대한 마케팅 지출', 2, '성숙기에는 시장 성장이 둔화되고 가격 경쟁이 심화되므로 비용 절감, 효율화, 현금흐름 극대화 전략이 중요하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 11, '04', 'Porter 5 Forces', '공급자 교섭력이 강해지는 조건으로 가장 적절한 것은?', '공급자 수가 많고 대체 공급처가 풍부할 때', '공급자가 소수이고 원자재 전환비용이 높을 때', '구매자가 대량 구매할 때', '제품이 표준화되어 있을 때', 1, '공급자가 소수(과점)이고 다른 공급처로의 전환이 어려울수록 공급자 교섭력이 강해진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 12, '04', 'Porter 5 Forces', '대체재 위협이 낮아지는 조건은?', '대체재의 기능이 우수하고 가격이 낮을 때', '소비자가 현 제품에 높은 충성도를 갖고 전환비용이 높을 때', '대체재 기업이 많을 때', '규제가 없을 때', 1, '소비자의 브랜드 충성도가 높고 다른 제품으로 바꾸는 전환비용이 높을수록 대체재 위협은 낮아진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 13, '04', '반도체 KPI', '반도체 산업에서 중요한 KPI로 활용되는 ASP(Average Selling Price)란?', '평균 생산 비용', '평균 판매 가격', '평균 재고 회전율', '평균 시장 점유율', 1, 'ASP(Average Selling Price)는 제품의 평균 판매 가격으로, 반도체 수요·공급 균형과 가격 결정력을 파악하는 데 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 14, '04', '2차전지 KPI', '2차전지(배터리) 산업에서 핵심 KPI 중 에너지 밀도를 나타내는 단위는?', 'Wh/kg', 'km/L', 'GHz', 'MW', 0, '에너지 밀도(Wh/kg 또는 Wh/L)는 단위 중량 또는 부피당 저장할 수 있는 에너지량으로 배터리 성능의 핵심 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 15, '04', '산업분석', '산업분석에서 경쟁강도(rivalry)가 높아지는 조건이 아닌 것은?', '경쟁사 수가 많을 때', '산업 성장률이 낮을 때', '제품 차별화가 낮을 때', '진입장벽이 매우 높을 때', 3, '진입장벽이 높으면 새로운 경쟁자가 진입하기 어려우므로 오히려 기존 경쟁강도는 낮아지는 효과가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 16, '04', 'SWOT', 'SO 전략(강점-기회 전략)이란?', '약점을 보완하여 위협을 회피하는 전략', '강점을 활용하여 기회를 포착하는 공격적 전략', '약점을 보완하여 기회를 살리는 전략', '강점을 활용하여 위협에 대응하는 전략', 1, 'SO 전략은 내부 강점(S)을 활용하여 외부 기회(O)를 극대화하는 공격적 전략이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 17, '04', 'PEST', 'PEST 분석에서 금리 인상은 어느 요소에 해당하는가?', '정치(Political)', '경제(Economic)', '사회(Social)', '기술(Technological)', 1, '금리는 경제적 환경 요인(Economic)에 해당하며 기업의 자본 비용과 소비·투자에 직접 영향을 준다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 18, '04', '산업수명주기', '쇠퇴기 산업의 특징으로 가장 적절한 것은?', '신규 진입자 급증', '시장 수요 급성장', '매출 감소, 기업 퇴출·구조조정', '고마진 유지', 2, '쇠퇴기에는 기술 변화나 수요 감소로 시장이 줄어들고 기업들이 시장을 떠나거나 구조조정하는 단계이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 19, '04', 'Porter 5 Forces', 'Porter 5 Forces 분석의 주요 목적은?', '기업의 내부 자원을 평가하는 것', '산업 내 경쟁 강도와 수익성을 평가하는 것', '개별 기업의 주가를 예측하는 것', '정부 정책을 분석하는 것', 1, 'Porter 5 Forces는 산업의 구조적 매력도와 수익성을 결정하는 경쟁 요인을 분석하는 프레임워크이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 20, '04', '바이오 KPI', '바이오/제약 산업에서 임상시험 성공 확률이 중요한 이유는?', '임상 성공 시 환자 수가 줄어들기 때문', '임상 성공 여부가 기업 가치와 파이프라인 가치를 직접 결정하기 때문', '임상은 비용이 들지 않기 때문', '임상 결과는 주가에 영향을 주지 않기 때문', 1, '바이오 기업의 가치는 신약 파이프라인에 의존하므로 임상 성공 확률(POC, Phase I~III)이 핵심 KPI이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 21, '04', '산업분석', '규모의 경제(economies of scale)가 진입장벽이 되는 이유는?', '대규모 생산으로 단위당 원가를 낮추어 신규 진입자가 가격 경쟁에서 불리하기 때문', '규모가 클수록 마케팅 비용이 감소하기 때문', '대기업만이 특허를 보유할 수 있기 때문', '소규모 기업은 법적으로 시장 진입이 불가능하기 때문', 0, '기존 기업이 대량 생산으로 단위 원가를 낮추면 신규 진입자는 초기 소규모 생산으로 원가 경쟁에서 불리하여 진입장벽이 된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 22, '04', 'SWOT', 'WT 전략(약점-위협 전략)의 목적은?', '공격적 성장', '약점과 위협을 최소화하는 방어적 전략', '강점을 활용한 시장 확대', '새로운 시장 개척', 1, 'WT 전략은 기업의 약점을 보완하면서 외부 위협을 회피하는 방어적 생존 전략이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 23, '04', '산업수명주기', '도입기 산업에 투자할 때의 주요 리스크는?', '시장 포화로 성장이 없음', '기술 불확실성이 높고 수익화 시점이 불명확함', '경쟁사가 너무 많음', '배당수익률이 낮음', 1, '도입기는 기술의 상용화 여부, 고객 수용성, 수익화 시점 등이 불확실하여 투자 리스크가 크다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 24, '04', 'Porter 5 Forces', '전략적으로 가장 매력적인 산업 구조는?', '진입장벽 낮음, 대체재 많음, 구매자 교섭력 강함', '진입장벽 높음, 대체재 적음, 공급자/구매자 교섭력 약함', '경쟁사 수 많음, 공급자 교섭력 강함', '진입장벽 낮음, 경쟁 약함', 1, '5 Forces 관점에서 진입장벽이 높고 대체재가 적으며 공급자·구매자 교섭력이 낮은 산업이 가장 수익성이 높다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 25, '04', 'PEST', 'PEST 분석에서 AI·자동화 기술 발전은 어느 요소에 해당하는가?', '정치', '경제', '사회', '기술', 3, 'AI, 자동화 등 기술 혁신은 PEST의 기술(Technological) 요소에 해당한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 26, '04', '반도체 KPI', '반도체 산업에서 수율(yield)이란?', '웨이퍼당 칩 생산량', '생산된 웨이퍼 중 불량 없이 합격한 칩의 비율', '메모리 용량 단위', '칩 설계 비용', 1, '수율은 전체 생산 칩 중 품질 기준을 통과한 양품 비율로, 수율이 높을수록 원가 경쟁력이 강해진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 27, '04', '산업수명주기', '성장기에서 성숙기로 전환될 때 나타나는 변화는?', '시장 성장률 가속', '가격 경쟁 심화와 마진 압박', '신규 진입자 급증', '기술 혁신 활발', 1, '성숙기로 접어들면 시장이 포화 상태가 되어 기업 간 가격 경쟁이 치열해지고 마진이 압박을 받는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 28, '04', 'SWOT', 'SWOT 분석의 한계점으로 가장 적절한 것은?', '내부 요인 분석이 불가능하다', '정적(static) 분석으로 환경 변화의 속도를 반영하기 어렵다', '외부 환경을 전혀 고려하지 않는다', '재무 데이터만 활용한다', 1, 'SWOT 분석은 특정 시점의 스냅샷으로 빠르게 변화하는 시장 환경을 동적으로 반영하기 어렵다는 한계가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 29, '04', 'Porter 5 Forces', '전환비용(switching cost)이 높으면 어느 경쟁요인에 어떤 영향을 미치는가?', '구매자 교섭력 강화', '대체재 위협 강화', '구매자 교섭력 약화 및 대체재 위협 약화', '공급자 교섭력 강화', 2, '전환비용이 높으면 소비자가 다른 브랜드나 제품으로 바꾸기 어려워 구매자 교섭력이 약해지고 대체재 위협도 낮아진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (4, 30, '04', '산업분석', '산업분석과 기업분석의 관계를 설명한 것으로 가장 적절한 것은?', '기업분석만 하면 산업분석은 불필요하다', '산업의 매력도가 낮아도 개별 기업이 좋으면 무조건 좋은 투자이다', '좋은 산업에 있는 기업이 유리하지만, 기업 고유 역량도 중요하다', '산업 성장률이 높으면 모든 기업의 주가가 상승한다', 2, '투자 분석에서 산업 구조와 성장성은 중요한 배경이지만 개별 기업의 경쟁력과 재무 건전성도 함께 평가해야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 1, '05', 'DART', 'DART(Data Analysis, Retrieval and Transfer System)는 어떤 기관이 운영하는가?', '한국거래소(KRX)', '금융감독원(FSS)', '기획재정부', '한국은행', 1, 'DART는 금융감독원이 운영하는 전자공시시스템으로 상장기업의 사업보고서, 분기보고서 등을 공시한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 2, '05', 'DART', '기업이 DART에 공시해야 하는 주요 정기 보고서가 아닌 것은?', '사업보고서(연간)', '분기보고서(1·3분기)', '반기보고서(2분기)', '일간 매출 보고서', 3, 'DART 정기공시는 사업보고서(연간), 반기보고서(반기), 분기보고서(1·3분기) 등이다. 일간 매출 보고서는 공시 의무가 없다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 3, '05', 'DART', '유상증자 공시를 주목해야 하는 이유는?', '이익이 늘기 때문', '주식 수 증가로 기존 주주의 지분이 희석될 수 있기 때문', '배당이 자동으로 증가하기 때문', '주가가 항상 상승하기 때문', 1, '유상증자는 신주를 발행하여 자금을 조달하므로 주식 수가 늘어 기존 주주의 지분율이 낮아지는 희석 효과가 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 4, '05', 'DART', '자사주 취득 공시가 주가에 긍정적으로 해석되는 이유는?', '기업이 직원 급여를 올리기 때문', '유통 주식 수 감소로 주당 가치가 높아질 수 있기 때문', '부채가 줄어들기 때문', '매출이 자동으로 늘기 때문', 1, '자사주 취득은 시장에서 유통되는 주식 수를 줄여 주당 순이익(EPS)을 높이고 주주가치를 제고하는 효과가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 5, '05', 'DART', '수주 공시가 중요한 산업으로 가장 적절한 것은?', '소매유통', '조선·건설·방산', '식품', '금융', 1, '수주 공시는 미래 매출 예상액을 나타내므로 수주 기반으로 운영되는 조선·건설·방산 기업에서 특히 중요하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 6, '05', 'Peer Comparison', 'Peer Comparison(동종업체 비교) 분석의 목적은?', '단일 기업의 절대적 가치만 평가', '동일 산업 내 경쟁사와 비교하여 상대적 가치와 강점을 파악', '기업의 역사적 성과만 분석', '경쟁사 기밀 정보 수집', 1, 'Peer Comparison은 동일 산업 내 유사 기업들과 재무지표, 밸류에이션 등을 비교하여 상대적 매력도를 평가하는 분석 방법이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 7, '05', 'Peer Comparison', 'Peer Comparison에서 비교 기업(peer)을 선정할 때 가장 중요한 기준은?', '본사 위치가 같은 기업', '동일하거나 유사한 사업 모델과 시장', '창업 연도가 같은 기업', '직원 수가 비슷한 기업', 1, 'Peer는 동일한 산업과 사업 모델, 유사한 시장에서 경쟁하는 기업으로 선정해야 의미 있는 비교가 가능하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 8, '05', '산업 KPI', '소매업에서 핵심 KPI로 사용되는 SSS(Same Store Sales)란?', '신규 점포의 매출', '기존 점포(일정 기간 이상 운영)의 매출 성장률', '전체 매출 합계', '온라인 채널 매출', 1, 'SSS(Same Store Sales, 기존점 매출)는 신규 점포 효과를 제외한 기존 점포의 매출 증감을 측정하여 실질 성장을 파악하는 KPI이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 9, '05', '산업 KPI', '인터넷/플랫폼 기업에서 MAU가 의미하는 것은?', '월간 활성 사용자(Monthly Active Users)', '월 평균 수익(Monthly Average Revenue)', '최대 접속 사용자', '분기 사용자 증가율', 0, 'MAU(Monthly Active Users)는 월간 활성 사용자 수로 플랫폼 기업의 트래픽과 성장성을 측정하는 핵심 KPI이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 10, '05', '산업 KPI', 'SaaS 기업에서 NRR(Net Revenue Retention)이 100%를 초과한다는 의미는?', '신규 고객 유치에 실패함', '기존 고객으로부터의 매출이 해지 없이 확장되어 순 증가함', '비용이 매출을 초과함', '해지율이 100%임', 1, 'NRR이 100% 이상이면 기존 고객 내에서 업셀·확장으로 매출이 순증가하고 있어 비즈니스 건전성이 높음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 11, '05', '산업 KPI', 'ARPU(Average Revenue Per User)가 중요한 산업은?', '건설업', '통신·구독 서비스·게임', '농업', '해운업', 1, 'ARPU는 사용자당 평균 매출로 통신, 구독 서비스, 게임, OTT 등 사용자 기반 비즈니스에서 핵심 KPI로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 12, '05', 'DART', '경영권 변경 공시(최대주주 변경)가 중요한 이유는?', '매출 변화를 직접 나타내기 때문', '회사의 지배구조와 경영 방향이 바뀔 수 있기 때문', '세금이 변경되기 때문', '주식 수가 늘기 때문', 1, '최대주주 변경은 경영 방향, 전략, 지배구조 전반의 변화를 초래할 수 있어 투자자에게 중요한 공시이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 13, '05', '산업 KPI', '호텔·숙박업의 핵심 KPI인 RevPAR는?', '실내 가용 객실 1실당 수익', '평균 숙박 일수', '전체 호텔 매출 합계', '직원당 매출', 0, 'RevPAR(Revenue Per Available Room)는 가용 객실 1실당 수익으로 객실 점유율과 평균 객실 요금을 동시에 반영하는 호텔 KPI이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 14, '05', 'Peer Comparison', 'PER를 이용한 Peer Comparison 시 주의사항은?', '모든 산업에 동일 PER 기준 적용', '산업별 적정 PER 수준이 다르므로 동일 업종끼리 비교해야 한다', 'PER은 성장주에는 사용 불가', 'PER이 낮으면 무조건 저평가이다', 1, '성장산업과 성숙산업의 적정 PER이 다르므로 반드시 동종업체 간 비교가 의미 있다. 낮은 PER이 저평가의 충분 조건은 아니다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 15, '05', '산업 KPI', '금융업(은행)에서 NIM(Net Interest Margin)이란?', '순이익을 총자산으로 나눈 비율', '대출 이자율과 예금 이자율의 차이로 발생하는 순이자 마진', '비이자 수익 비율', '부실채권 비율', 1, 'NIM(순이자마진)은 은행이 자금을 운용하여 벌어들인 이자수익과 조달 이자비용의 차이로 은행의 핵심 수익성 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 16, '05', '산업 KPI', '제조업에서 가동률(utilization rate)이 중요한 이유는?', '직원 만족도를 나타내기 때문', '설비 활용 정도를 통해 고정비 흡수 효율과 수익성을 파악할 수 있기 때문', '환경 규제와 관련이 있기 때문', '정부 보조금 신청 기준이기 때문', 1, '가동률이 높을수록 고정비를 더 많은 생산량으로 흡수하여 단위당 원가가 낮아지므로 수익성 개선에 기여한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 17, '05', 'DART', '분기보고서 공시 기한은 분기 종료 후 몇 일 이내인가?', '15일', '30일', '45일', '90일', 2, '상장법인은 분기 종료 후 45일 이내에 분기보고서를 제출해야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 18, '05', 'Peer Comparison', 'EV/EBITDA를 Peer Comparison에 활용할 때의 장점은?', '자본구조와 감가상각 방식 차이를 제거하여 기업 간 비교가 용이하다', 'EPS가 마이너스여도 사용 가능하다는 점이 유일한 장점이다', '세금 차이를 반영하지 않는다', 'PER과 항상 동일한 결과를 준다', 0, 'EV/EBITDA는 부채·자본 구조(EV)와 감가상각비 차이를 제거하여 순수한 영업 현금 창출력으로 기업 간 비교를 가능하게 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 19, '05', '산업 KPI', 'E-커머스(전자상거래) 기업의 핵심 KPI인 GMV란?', '총 상품 판매액(Gross Merchandise Value)', '순이익 합계', '광고 수익', '월간 활성 사용자', 0, 'GMV(Gross Merchandise Value)는 플랫폼에서 거래된 총 상품 판매액으로 E-커머스 기업의 규모와 성장을 측정하는 핵심 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 20, '05', 'DART', '임원·대주주 주식 매매 공시를 확인하는 이유는?', '기업 배당을 계산하기 위해', '내부자의 매수·매도 동향이 기업 가치에 대한 시그널이 될 수 있기 때문', '세금을 계산하기 위해', '주식 분할 정보를 얻기 위해', 1, '임원과 대주주는 기업 내부 정보에 접근할 수 있으므로 그들의 주식 거래는 기업 전망에 대한 내부자 시그널로 해석된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 21, '05', '산업 KPI', '항공사의 주요 KPI인 Load Factor(탑승률)가 중요한 이유는?', '항공기 무게와 관련이 있기 때문', '매 항공편의 고정비를 얼마나 효율적으로 회수하는지 보여주기 때문', '연료 효율을 직접 측정하기 때문', '직원 수와 비례하기 때문', 1, '탑승률(Load Factor)이 높을수록 고정비(항공기 운항비)를 더 많은 승객이 부담하여 수익성이 개선된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 22, '05', 'Peer Comparison', '동종업체 비교에서 멀티플 프리미엄이 부여되는 경우는?', '성장률이 낮고 부채가 많을 때', '성장률이 높고 수익성이 우수하며 경쟁 우위가 명확할 때', '배당수익률이 낮을 때', '기업 규모가 작을 때', 1, '성장성과 수익성이 경쟁사보다 우수하고 지속 가능한 경쟁 우위가 있는 기업에는 상대적으로 높은 밸류에이션 멀티플이 적용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 23, '05', '산업 KPI', '반도체 장비/소재 기업에서 Book-to-Bill Ratio가 1을 초과하면?', '수주가 출하보다 많아 향후 매출 증가 기대', '출하가 수주보다 많아 재고 증가', '적자 상태', '시장 점유율 하락', 0, 'Book-to-Bill Ratio = 수주/출하로 1 초과이면 수주가 출하보다 많아 백로그가 쌓이고 있어 향후 매출 증가를 예고한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 24, '05', 'DART', '공정공시(Fair Disclosure)의 목적은?', '재무제표를 특정 기관에 먼저 제공하기 위해', '모든 투자자에게 중요 정보를 동시에 공개하여 정보 비대칭을 해소하기 위해', '외국인 투자자를 위한 영문 공시', '소액주주만을 위한 정보 제공', 1, '공정공시는 기업이 애널리스트나 대형 기관투자자에게 선택적으로 정보를 제공하는 것을 방지하고 모든 시장 참여자에게 동시에 공시하는 제도이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 25, '05', '산업 KPI', '구독 경제(Subscription) 기업에서 Churn Rate(해지율)이 낮을수록 좋은 이유는?', '비용이 낮아지기 때문', '기존 고객 유지율이 높아 반복 매출이 안정적으로 유지되기 때문', '신규 고객 유치 비용이 늘기 때문', 'ARPU가 자동으로 하락하기 때문', 1, '해지율이 낮으면 기존 고객이 오래 유지되어 LTV(고객 생애 가치)가 높아지고 CAC(고객 획득 비용) 대비 수익성이 개선된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 26, '05', 'Peer Comparison', 'Forward PER와 Trailing PER의 차이는?', '동일하다', 'Forward PER는 예상(미래) 이익 기준, Trailing PER는 실적(과거) 이익 기준', 'Trailing PER가 항상 낮다', 'Forward PER는 시가총액을 사용하지 않는다', 1, 'Forward PER는 향후 12개월 예상 EPS 기준으로 성장 기대를 반영하고, Trailing PER는 과거 12개월 실제 EPS 기준으로 현재 가치를 반영한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 27, '05', '산업 KPI', '물류·택배 기업의 핵심 KPI인 CPC(Cost Per Carton)란?', '박스 1개당 처리 비용', '박스 1개당 배송 수익', '전체 물류비', '직원당 처리 건수', 0, 'CPC는 상자(carton) 1개를 처리하는 데 드는 비용으로 물류 효율성을 측정하는 KPI이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 28, '05', 'DART', '잠정 실적 공시와 확정 실적 공시의 차이는?', '동일하다', '잠정 실적은 감사 전 추정치이고 확정 실적은 외부감사 완료 후 확인된 수치이다', '잠정 실적만 DART에 공시된다', '확정 실적은 IR 행사에서만 발표된다', 1, '잠정 실적은 회계연도 종료 후 외부감사 전 발표되는 추정치이고, 확정 실적은 감사 완료 후 공시되는 최종 재무 수치이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 29, '05', '산업 KPI', 'ROE(Return on Equity)가 Peer Comparison에서 중요한 이유는?', '부채를 포함한 전체 자산의 수익성을 보여주기 때문', '주주 자본 대비 얼마나 효율적으로 이익을 창출하는지 비교할 수 있기 때문', '시가총액을 반영하기 때문', '세전 이익을 기준으로 하기 때문', 1, 'ROE는 주주 자본을 기준으로 이익 창출 효율성을 보여주어 동종업체 간 경영 효율성 비교에 유용한 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (5, 30, '05', 'DART', '수시공시(수시보고서)가 필요한 경우가 아닌 것은?', '주요 계약 체결', '대규모 자산 처분', '경영진 이메일 발송', '최대주주 변경', 2, '수시공시는 기업에 중요한 영향을 미치는 사건(계약, 자산 처분, 지배구조 변경 등)이 발생할 때 즉시 공시해야 한다. 내부 이메일은 공시 대상이 아니다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 1, '06', '손익계산서', '손익계산서에서 매출총이익(Gross Profit)의 계산식은?', '매출액 - 판관비', '매출액 - 매출원가', '영업이익 + 감가상각비', '당기순이익 + 이자비용', 1, '매출총이익 = 매출액 - 매출원가로, 제품 생산 원가를 제외한 기본 수익성을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 2, '06', '손익계산서', '영업이익의 계산식은?', '매출총이익 - 판매비와관리비', '매출액 - 매출원가', '당기순이익 + 법인세', '매출총이익 + 영업외이익', 0, '영업이익 = 매출총이익 - 판매비와관리비(판관비)로, 영업활동에서 발생한 순수 이익이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 3, '06', '손익계산서', '당기순이익(Net Income)과 영업이익의 차이는?', '동일하다', '당기순이익은 영업이익에서 이자, 세금 등을 추가 반영한 최종 이익이다', '영업이익이 항상 더 작다', '당기순이익은 세전 이익이다', 1, '영업이익은 영업활동에서의 이익이고, 당기순이익은 여기에 영업외손익(이자, 투자손익), 법인세를 모두 반영한 최종 이익이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 4, '06', '매출총이익률', '매출총이익률(Gross Margin)이 높다는 것의 의미는?', '비용 전체가 낮다', '제품의 가격 결정력이 강하거나 원가 효율성이 높다', '영업이익이 반드시 높다', '순이익이 반드시 높다', 1, '매출총이익률이 높다는 것은 원가 대비 높은 가격을 받을 수 있는 가격 결정력이나 원가 절감 능력이 있음을 의미한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 5, '06', '고정비/변동비', '매출이 증가해도 총액이 변하지 않는 비용은?', '변동비', '고정비', '한계비용', '재료비', 1, '고정비는 생산량이나 매출 변화에 관계없이 일정하게 발생하는 비용이다. 임대료, 감가상각비, 고정 급여 등이 해당된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 6, '06', '고정비/변동비', '단위당 생산량에 비례하여 증가하는 비용은?', '고정비', '감가상각비', '변동비', '임대료', 2, '변동비는 생산량이나 매출에 비례하여 증가하는 비용이다. 재료비, 판매 수수료, 포장비 등이 대표적이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 7, '06', '손익분기점', '손익분기점(BEP, Break-Even Point)의 정의는?', '최대 이익이 발생하는 매출 수준', '총 수익과 총 비용이 같아지는 매출 수준', '영업이익률이 최대인 수준', '변동비가 0이 되는 수준', 1, 'BEP는 총수익(매출)과 총비용이 일치하여 이익도 손실도 없는 매출 수준으로 고정비 ÷ (단위당 판매가 - 단위당 변동비)로 계산된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 8, '06', '손익분기점', 'BEP 계산 공식에서 "공헌이익"이란?', '매출액 - 고정비', '매출액 - 변동비', '영업이익 + 감가상각', '순이익 + 이자', 1, '공헌이익(Contribution Margin) = 매출액 - 변동비로 고정비를 회수하고 이익을 창출하는 데 기여하는 금액이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 9, '06', '영업레버리지', '영업레버리지(Operating Leverage)가 높다는 것의 의미는?', '변동비 비중이 높다', '고정비 비중이 높아 매출 증가 시 영업이익이 더 빠르게 증가한다', '부채 비율이 높다', '감가상각비가 없다', 1, '고정비 비중이 높으면 매출이 증가할 때 고정비는 그대로이므로 영업이익이 매출 증가율보다 더 빠르게 늘어나는 레버리지 효과가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 10, '06', '영업레버리지', 'DOL(Degree of Operating Leverage) 계산 공식은?', '영업이익 증가율 / 매출 증가율', '매출 증가율 / 영업이익 증가율', '공헌이익 / 영업이익', '순이익 / 영업이익', 0, 'DOL = 영업이익 증가율 / 매출액 증가율로 매출 1% 변화 시 영업이익이 몇 % 변화하는지를 나타낸다. 또한 공헌이익/영업이익으로도 계산된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 11, '06', '이자보상배율', '이자보상배율(Interest Coverage Ratio)의 계산 공식은?', '영업이익 / 이자비용', '당기순이익 / 이자비용', '매출액 / 부채', '순이익 / 매출액', 0, '이자보상배율 = 영업이익 / 이자비용으로 기업이 영업이익으로 이자를 얼마나 감당할 수 있는지를 나타내는 안전성 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 12, '06', '이자보상배율', '이자보상배율이 1 미만이면 의미하는 것은?', '재무구조가 우량하다', '영업이익으로 이자비용도 충당하지 못하여 재무적 위험이 높다', '부채가 없다는 의미이다', '투자를 늘려야 한다', 1, '이자보상배율 1 미만은 영업이익이 이자비용보다 작다는 뜻으로 영업활동으로 이자도 못 갚는 위험한 상태이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 13, '06', '판관비', '판매비와관리비(SG&A)에 포함되는 항목은?', '원자재 구매비', '공장 직접 인건비', '영업사원 급여, 광고비, 본사 임대료', '제품 운송비만', 2, '판관비(SG&A)는 제품 생산 원가 외에 기업 운영에 필요한 영업(Sales), 일반(General), 관리(Administrative) 비용을 포함한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 14, '06', '손익계산서', 'EBITDA가 영업이익보다 큰 이유는?', '이자비용이 포함되기 때문', '감가상각비와 무형자산상각비가 현금 유출이 없는 비용이라 다시 더해지기 때문', '세금이 제외되기 때문', '매출원가가 낮아지기 때문', 1, 'EBITDA = 영업이익 + 감가상각비 + 상각비로 현금 유출이 없는 회계적 비용을 다시 더하므로 영업이익보다 크다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 15, '06', '손익분기점', '고정비가 10억원, 단위당 판매가 5만원, 단위당 변동비 3만원일 때 BEP 수량은?', '2만 개', '3만 3천 개', '5만 개', '10만 개', 2, 'BEP = 고정비 / 공헌이익 = 10억 / (5만-3만) = 10억 / 2만 = 50,000개이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 16, '06', '영업레버리지', '영업레버리지가 높은 기업의 특징은?', '매출 하락 시에도 영업이익이 안정적이다', '매출 하락 시 영업이익이 더 빠르게 감소하는 리스크가 있다', '변동비가 많다', '부채가 전혀 없다', 1, '고정비 비중이 높으면 매출이 줄 때도 고정비는 그대로 발생하여 영업이익이 매출 하락보다 더 큰 폭으로 감소하는 양방향 레버리지 리스크가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 17, '06', '손익계산서', '영업이익률(Operating Margin) 계산식은?', '영업이익 / 매출액 × 100', '순이익 / 매출액 × 100', 'EBITDA / 매출액 × 100', '매출총이익 / 영업이익 × 100', 0, '영업이익률 = (영업이익 / 매출액) × 100으로 매출에서 영업이익이 차지하는 비율이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 18, '06', '손익계산서', '순이익률(Net Margin)이 영업이익률보다 낮은 일반적 이유는?', '감가상각비가 높기 때문', '이자비용과 법인세가 추가로 차감되기 때문', '매출원가가 높기 때문', '판관비가 높기 때문', 1, '순이익은 영업이익에서 영업외비용(이자비용 등)과 법인세를 추가로 차감하므로 순이익률이 영업이익률보다 낮다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 19, '06', '손익계산서', '동일한 매출액에서 고정비를 줄이면 BEP에 어떤 영향이 있는가?', 'BEP가 높아진다', 'BEP가 낮아진다', 'BEP 변화 없다', '변동비가 증가한다', 1, 'BEP = 고정비 / 공헌이익이므로 고정비가 줄어들면 BEP(손익분기매출)가 낮아져 더 낮은 매출에서도 이익을 낼 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 20, '06', '손익계산서 구조', '다음 손익계산서 항목을 순서대로 나열한 것은?', '매출액→영업이익→매출총이익→당기순이익', '매출액→매출총이익→영업이익→당기순이익', '매출총이익→매출액→영업이익→당기순이익', '영업이익→매출액→매출총이익→당기순이익', 1, '손익계산서는 매출액→매출원가→매출총이익→판관비→영업이익→영업외손익→세전이익→법인세→당기순이익 순으로 구성된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 21, '06', '감가상각', '감가상각비(Depreciation)가 손익계산서에 미치는 영향은?', '현금 유출 없이 비용으로 계상되어 영업이익을 감소시킨다', '현금 유출과 동시에 비용 처리된다', '자산 가치를 증가시킨다', '매출원가에는 포함되지 않는다', 0, '감가상각비는 유형자산의 취득원가를 내용연수에 걸쳐 배분하는 회계적 비용으로 현금 유출 없이 이익을 줄인다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 22, '06', '공헌이익', '공헌이익률(Contribution Margin Ratio)이 60%라는 의미는?', '매출의 60%가 순이익이다', '매출 1원 중 60전이 고정비 회수와 이익에 기여한다', '변동비가 60%이다', '고정비가 60%이다', 1, '공헌이익률 = 공헌이익 / 매출액으로 매출 1원 중 변동비를 제외하고 고정비 회수와 이익 창출에 기여하는 비율이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 23, '06', '손익계산서', '영업외수익의 예로 적절한 것은?', '제품 판매 수익', '이자수익, 투자주식 배당수익', '임직원 급여', '원자재 구매비', 1, '영업외수익은 주된 영업활동 외에서 발생하는 수익으로 이자수익, 배당수익, 자산처분이익 등이 해당된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 24, '06', '손익분기점', '안전한계율(Margin of Safety)이란?', '현재 매출액이 BEP를 초과하는 비율', '최대 가능 손실 비율', '부채 대비 자본 비율', '변동비 비율', 0, '안전한계율 = (현재 매출 - BEP 매출) / 현재 매출로, 매출이 얼마나 감소해야 손실이 나는지를 나타내는 안전 마진이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 25, '06', '영업레버리지', '소프트웨어 기업이 높은 영업레버리지를 갖는 이유는?', '재료비가 많기 때문', '소프트웨어 개발에 고정비(인건비·R&D)가 크고 복제 한계비용이 거의 0이기 때문', '규제가 적기 때문', '변동비 비중이 높기 때문', 1, '소프트웨어는 초기 개발에 막대한 고정비가 들지만 추가 판매(복제)비용이 거의 없어 매출 증가 시 이익이 급격히 늘어나는 고영업레버리지 구조이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 26, '06', '손익계산서', '매출원가율(COGS/Revenue)이 상승하면 어떤 영향이 있는가?', '매출총이익률 개선', '매출총이익률 하락', '영업이익률 개선', '순이익률 개선', 1, '매출원가율 = COGS/Revenue가 높아지면 매출총이익(Revenue-COGS)이 줄어 매출총이익률이 하락한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 27, '06', '손익계산서', '일회성 항목(one-time item)을 제외한 정상적인 이익 수준을 파악하기 위한 지표는?', '당기순이익', '조정 영업이익(Adjusted Operating Income)', '매출총이익', '법인세 비용', 1, '구조조정비, 자산손상 등 일회성 항목을 제거한 조정 영업이익은 기업의 반복 가능한 핵심 수익성을 파악하는 데 유용하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 28, '06', '이자보상배율', '이자보상배율이 3배라는 의미는?', '부채가 자본의 3배이다', '영업이익이 이자비용의 3배여서 이자를 충분히 감당할 수 있다', '매출이 이자비용의 3배이다', '순이익이 이자비용의 3배이다', 1, '이자보상배율 3배는 영업이익이 이자비용의 3배로 이자를 지급하고도 충분한 여유가 있음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 29, '06', '손익계산서', 'R&D 비용을 모두 당기 비용으로 처리할 때 나타나는 영향은?', '당기 영업이익 증가', '당기 영업이익 감소, 미래 수익 기반 반영 어려움', '자산 증가', '부채 감소', 1, 'R&D를 당기 비용 처리하면 현재 영업이익을 낮추지만 미래 수익을 창출할 무형자산이 재무제표에 반영되지 않는 한계가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (6, 30, '06', '손익계산서', '같은 매출액에서 영업이익률이 개선되는 방법은?', '매출원가 또는 판관비를 줄이는 것', '이자비용을 늘리는 것', '법인세율을 높이는 것', '자본금을 늘리는 것', 0, '영업이익률 = 영업이익/매출액이므로 동일 매출에서 매출원가와 판관비를 절감하면 영업이익이 늘어 이익률이 개선된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 1, '07', '현금흐름표', '현금흐름표의 3가지 활동 구분이 올바른 것은?', '영업·투자·재무', '생산·판매·관리', '유입·유출·순변동', '단기·중기·장기', 0, '현금흐름표는 영업활동(CFO), 투자활동(CFI), 재무활동(CFF)의 3가지 섹션으로 구성된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 2, '07', '현금흐름표', '영업활동 현금흐름(CFO)이 높다는 것의 의미는?', '부채가 많다는 뜻이다', '본업에서 현금을 잘 창출하고 있다는 신호이다', '투자를 많이 한다는 뜻이다', '배당금을 많이 준다는 뜻이다', 1, 'CFO가 높으면 주된 영업활동에서 현금이 충분히 창출되어 자금 조달 없이도 사업을 운영할 수 있음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 3, '07', '현금흐름표', '이상적인 성숙 기업의 현금흐름 패턴은?', 'CFO 마이너스, CFI 플러스, CFF 플러스', 'CFO 플러스, CFI 마이너스, CFF 마이너스', 'CFO 플러스, CFI 플러스, CFF 플러스', 'CFO 마이너스, CFI 마이너스, CFF 마이너스', 1, '성숙 기업은 영업에서 현금을 벌고(CFO+), 미래를 위해 투자하며(CFI-), 부채 상환과 배당을 지급(CFF-)하는 패턴이 이상적이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 4, '07', 'FCF', '잉여현금흐름(FCF, Free Cash Flow)의 계산식은?', '영업이익 - 법인세', 'CFO - 자본적지출(Capex)', '당기순이익 + 감가상각비', '매출액 - 변동비', 1, 'FCF = 영업활동 현금흐름(CFO) - 자본적지출(Capex)로 기업이 사업 유지·확장 투자 후 자유롭게 사용할 수 있는 현금이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 5, '07', 'FCF', 'FCF가 높은 기업이 할 수 있는 활동이 아닌 것은?', '배당 지급', '자사주 매입', '부채 상환', '법인세 면제', 3, 'FCF가 높으면 주주환원(배당·자사주), 부채 상환, 추가 투자 등 재무적 유연성이 커진다. 법인세 면제는 FCF와 무관하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 6, '07', 'DCF', 'DCF(Discounted Cash Flow) 가치평가의 핵심 개념은?', '과거 이익을 평균하여 가치를 산정한다', '미래에 발생할 현금흐름을 현재가치로 할인하여 기업 가치를 구한다', '시가총액과 장부가를 비교한다', '업종 평균 PER를 적용한다', 1, 'DCF는 기업이 미래에 창출할 잉여현금흐름(FCF)을 적정 할인율(WACC)로 현재가치화하여 내재가치를 산출하는 방법이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 7, '07', 'DCF', 'DCF 분석에서 할인율이 높아지면 기업 가치는?', '증가한다', '변화 없다', '감소한다', '두 배가 된다', 2, '할인율이 높을수록 미래 현금흐름의 현재가치가 줄어들어 DCF로 산출한 기업 내재가치가 낮아진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 8, '07', 'WACC', 'WACC(가중평균자본비용)의 구성 요소는?', '자기자본비용과 타인자본비용을 자본구조 비율로 가중평균', '기준금리와 인플레이션율의 합', '영업이익률과 순이익률의 평균', 'PER와 PBR의 가중평균', 0, 'WACC = (자기자본비용 × E/V) + (타인자본비용 × (1-세율) × D/V)로 자본과 부채의 비중으로 가중평균한 자본 조달 비용이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 9, '07', 'WACC', 'WACC가 낮아지면 DCF 기업가치에 어떤 영향을 미치는가?', '기업가치 하락', '기업가치 상승', '변화 없음', '매출 자동 증가', 1, 'WACC가 낮아지면 미래 현금흐름의 할인 정도가 줄어 현재가치가 높아지므로 DCF로 계산한 기업가치가 상승한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 10, '07', 'EVA', 'EVA(Economic Value Added)의 계산식은?', '매출액 - 비용', '세후 영업이익(NOPAT) - (투하자본 × WACC)', '영업이익 + 감가상각', '순이익 + 이자비용', 1, 'EVA = NOPAT - (투하자본 × WACC)로 자본 비용을 초과하는 진정한 경제적 이익을 측정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 11, '07', 'EVA', 'EVA가 양수(+)라는 것의 의미는?', '부채가 자본보다 많다', '기업이 투하된 자본의 기회비용을 초과하는 가치를 창출하고 있다', '매출이 증가하고 있다', '영업이익이 마이너스이다', 1, 'EVA > 0은 NOPAT이 WACC × 투하자본을 초과하여 주주가 요구하는 수익 이상의 가치를 창출하고 있음을 의미한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 12, '07', '현금흐름표', '투자활동 현금흐름(CFI)이 마이너스인 경우의 일반적 의미는?', '투자 실패', '설비투자·인수 등 미래를 위한 투자가 이루어지고 있다', '영업이 악화됐다', '배당을 줄인다', 1, 'CFI가 마이너스는 공장 신설, 설비 구매, 기업 인수 등 자산에 투자를 하고 있다는 뜻으로 성장 기업의 일반적인 패턴이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 13, '07', '현금흐름표', '재무활동 현금흐름(CFF)이 마이너스인 경우의 일반적 의미는?', '재무 구조가 악화되고 있다', '차입금 상환, 배당 지급, 자사주 매입 등 주주환원 및 부채 상환', '영업이 악화됐다', '신규 투자를 중단했다', 1, 'CFF 마이너스는 부채 상환, 배당, 자사주 매입 등 외부에 자금을 돌려주는 활동이 이루어지고 있음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 14, '07', 'DCF', 'DCF에서 터미널 밸류(Terminal Value)란?', '창업 첫 해의 현금흐름', '예측 기간 이후 영구히 발생하는 현금흐름의 현재가치', '부채의 만기 가치', '고정자산 잔존가치', 1, '터미널 밸류는 명시적 예측 기간(보통 5~10년) 이후 기업이 영구적으로 창출하는 FCF의 현재가치로 DCF 총가치의 많은 비중을 차지한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 15, '07', 'WACC', '타인자본비용(부채 이자율)에 (1-세율)을 곱하는 이유는?', '부채가 자기자본보다 비싸기 때문', '이자비용이 세금 공제 효과(tax shield)가 있기 때문', '세율이 항상 0이기 때문', '부채가 없을 때만 적용하기 때문', 1, '이자비용은 세전 비용으로 법인세 절감 효과(tax shield)가 있으므로 세후 타인자본비용 = 이자율 × (1-세율)로 계산된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 16, '07', 'FCF', 'Capex(자본적지출)가 높을 때 FCF에 미치는 영향은?', 'FCF 증가', 'FCF 감소', '변화 없음', 'CFO 자동 증가', 1, 'FCF = CFO - Capex이므로 Capex가 크면 FCF가 줄어든다. 그러나 미래 성장을 위한 투자라면 단기 FCF 감소는 긍정적으로 해석될 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 17, '07', 'WACC', '자기자본비용을 추정하는 데 일반적으로 사용하는 모형은?', 'CAPM(자본자산가격결정모형)', 'DCF 모형', '듀폰 분석', 'Gordon 성장 모형만', 0, 'CAPM(Capital Asset Pricing Model): 자기자본비용 = 무위험수익률 + 베타 × 시장 위험 프리미엄으로 자기자본비용을 추정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 18, '07', '현금흐름표', '순이익이 높아도 CFO가 낮을 수 있는 이유는?', '세금이 낮기 때문', '매출채권 증가, 재고 증가 등 운전자본 증가로 현금이 묶이기 때문', '감가상각비가 높기 때문', '이자수익이 포함되지 않기 때문', 1, '순이익이 높아도 매출채권·재고 등이 증가하면 현금이 실제로 유입되지 않아 CFO가 낮을 수 있다. 이를 이익의 질(quality of earnings) 문제라 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 19, '07', 'EVA', 'EVA가 지속적으로 마이너스인 기업의 문제점은?', '배당을 너무 많이 주는 것이다', '자본 비용보다 낮은 수익을 내어 주주 가치를 파괴하고 있다', '세금을 납부하지 않는다', '투자를 너무 많이 한다', 1, 'EVA < 0이 지속되면 기업이 자본 비용만큼의 수익도 못 내어 주주의 기대 수익률을 충족하지 못해 가치를 파괴하는 상태이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 20, '07', 'DCF', 'DCF 분석의 주요 한계점은?', '미래 현금흐름 예측과 할인율 설정의 불확실성이 크다', '과거 데이터를 사용하지 않는다', '산업분석이 필요 없다', '주가와 항상 일치하는 가치를 제공한다', 0, 'DCF는 미래 FCF 성장률과 WACC(할인율) 가정에 매우 민감하여 가정이 달라지면 결과가 크게 달라지는 한계가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 21, '07', 'FCF', '성장 단계의 기업이 FCF가 마이너스인 이유는?', '영업이 적자이기 때문', '미래 성장을 위해 Capex(투자)를 많이 집행하기 때문', '배당을 많이 주기 때문', '부채가 없기 때문', 1, '성장 기업은 공장, 설비, 기술 투자에 막대한 Capex를 집행하여 CFO보다 Capex가 클 수 있어 FCF가 마이너스가 되기도 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 22, '07', 'WACC', '부채 비중이 높아지면 WACC에 어떤 영향이 있는가?', 'WACC 항상 상승', '부채 비용이 자기자본보다 낮다면 WACC를 낮출 수 있으나 재무 위험이 커진다', 'WACC 변화 없음', '자기자본비용이 자동으로 하락한다', 1, '부채 이자율이 자기자본비용보다 낮으면 부채 비중 증가로 WACC를 낮출 수 있지만, 과도한 부채는 파산 위험을 높여 자기자본비용을 상승시킨다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 23, '07', '현금흐름표', '감가상각비를 CFO에 더하는(간접법) 이유는?', '감가상각비가 현금 유출을 수반하기 때문', '순이익에서 차감된 비용이지만 실제 현금이 나가지 않기 때문', '투자활동에 해당하기 때문', '법인세를 줄이기 위해서이다', 1, '간접법에서 감가상각비는 현금 유출 없이 손익계산서에서 차감된 비용이므로 순이익에 다시 더해 CFO를 산출한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 24, '07', 'DCF', 'DCF에서 영구성장률(terminal growth rate)이 너무 높으면 어떤 문제가 생기는가?', '기업가치가 과소평가된다', '기업가치가 과대평가될 수 있다', '감가상각비가 증가한다', '매출원가가 증가한다', 1, '영구성장률을 실제보다 높게 가정하면 터미널 밸류가 크게 부풀어 기업 전체 가치가 과대평가될 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 25, '07', 'EVA', 'NOPAT(세후영업이익)의 계산식은?', '영업이익 × (1-세율)', '당기순이익 + 이자비용', '매출액 - 변동비', '순이익 - 배당금', 0, 'NOPAT = 영업이익 × (1-법인세율)로 부채 이자 효과를 배제하고 영업에서 발생하는 세후 이익을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 26, '07', '현금흐름표', '운전자본(Working Capital)이 증가할 때 CFO에 미치는 영향은?', 'CFO 증가', 'CFO 감소', 'CFO 변화 없음', 'Capex 감소', 1, '매출채권·재고 증가 등 운전자본 증가는 현금이 외부로 묶인다는 의미로 간접법 CFO 계산 시 차감되어 CFO를 줄인다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 27, '07', 'FCF', 'FCFF(Free Cash Flow to Firm)와 FCFE(Free Cash Flow to Equity)의 차이는?', '동일하다', 'FCFF는 채권자·주주 모두에게 귀속되는 FCF이고, FCFE는 주주에게만 귀속되는 FCF이다', 'FCFE가 항상 더 크다', 'FCFF는 세전 기준, FCFE는 세후 기준이다', 1, 'FCFF(기업 잉여현금흐름)는 부채 이자 상환 전 자금으로 WACC로 할인하고, FCFE(주주 잉여현금흐름)는 이자 상환 후 주주 귀속분으로 자기자본비용으로 할인한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 28, '07', 'WACC', '무위험수익률(risk-free rate) 상승이 WACC에 미치는 영향은?', 'WACC 하락', 'WACC 상승', 'WACC 변화 없음', '타인자본비용만 감소', 1, '무위험수익률은 CAPM 자기자본비용의 기저가 되고 타인자본비용에도 영향을 미치므로, 무위험수익률 상승 시 WACC가 상승한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 29, '07', '현금흐름표', '현금흐름표와 손익계산서가 다른 결과를 보이는 가장 큰 이유는?', '세금 처리 방식이 다르기 때문', '발생주의(손익) vs. 현금주의(현금흐름)의 차이 때문', '환율 차이 때문', '계절성 효과 때문', 1, '손익계산서는 발생주의(수익·비용 인식)를, 현금흐름표는 현금주의(실제 현금 유출입)를 기반으로 작성되므로 동기간 수치가 다를 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (7, 30, '07', 'DCF', 'DCF와 상대가치 평가(PER, EV/EBITDA)의 가장 큰 차이점은?', 'DCF는 기업의 절대 내재가치를 추정하고, 상대가치는 시장 비교 기준이다', 'DCF가 더 간단하다', '상대가치만 미래를 반영한다', 'DCF는 소형주에만 사용된다', 0, 'DCF는 기업 고유의 현금흐름과 할인율로 절대 내재가치를 산출하고, 상대가치법은 유사 기업과 비교한 상대적 가치를 평가한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 1, '08', '티커', '한국 상장주식의 종목코드 형식은?', '알파벳 1~4자리', '6자리 숫자', '알파벳과 숫자의 혼합', '3자리 숫자', 1, '한국 주식 종목코드는 6자리 숫자로 구성된다. 예: 삼성전자 005930, 카카오 035720.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 2, '08', '티커', '미국 상장주식의 티커(ticker) 형식은?', '6자리 숫자', '1~4자리 알파벳', '국가코드 + 숫자', '숫자 + 알파벳 혼합', 1, '미국 주식 티커는 거래소별로 1~4자리 알파벳으로 구성된다. 예: AAPL(애플), TSLA(테슬라), AMZN(아마존).');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 3, '08', 'PER', 'PER(Price-to-Earnings Ratio)의 계산식은?', '주가 / 주당 매출액', '주가 / 주당 순이익(EPS)', '시가총액 / 순자산', '영업이익 / 주가', 1, 'PER = 주가 / EPS(주당순이익) = 시가총액 / 당기순이익으로 기업의 이익 대비 주가 수준을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 4, '08', 'PER', 'PER이 낮다는 것이 반드시 저평가를 의미하지 않는 이유는?', '이익이 크기 때문', '이익 성장률이 낮거나 기업에 구조적 문제가 있을 수 있기 때문', '주가가 낮기 때문', '배당을 많이 주기 때문', 1, 'PER이 낮아도 성장이 정체되거나 실적 악화 위험이 있으면 저평가가 아닌 "저평가 함정(value trap)"일 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 5, '08', 'PBR', 'PBR(Price-to-Book Ratio)의 계산식은?', '주가 / EPS', '주가 / BPS(주당순자산)', '시가총액 / 연 매출', 'EV / EBITDA', 1, 'PBR = 주가 / BPS(주당순자산) = 시가총액 / 순자산으로 자산 대비 주가 수준을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 6, '08', 'PBR', 'PBR이 1 미만이라는 것의 의미는?', '기업의 시장가치가 장부상 순자산보다 낮다', '기업이 적자이다', '주가가 고평가되어 있다', '부채가 자본보다 많다', 0, 'PBR < 1은 주가가 1주당 순자산(장부가)보다 낮게 평가되고 있다는 의미로, 저평가 신호일 수 있으나 사업 수익성 문제일 수도 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 7, '08', 'EV/EBITDA', 'EV(Enterprise Value)의 계산식은?', '시가총액만', '시가총액 + 순부채(부채 - 현금)', '매출액 + 영업이익', '순이익 × PER', 1, 'EV = 시가총액 + 순부채(총차입금 - 현금성자산)로 기업 전체를 인수할 때 필요한 실질 가치를 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 8, '08', 'EV/EBITDA', 'EV/EBITDA가 PER보다 기업 간 비교에 유리한 이유는?', 'EPS를 사용하기 때문', '자본구조와 세금, 감가상각 방식 차이를 제거하여 순수 영업 성과 비교가 가능하기 때문', '주가를 사용하지 않기 때문', '무형자산을 반영하기 때문', 1, 'EV/EBITDA는 자본 구조(EV), 감가상각정책, 세율 차이를 제거하므로 자본구조가 다른 기업 간, 국제 비교 시 PER보다 유용하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 9, '08', 'PSR', 'PSR(Price-to-Sales Ratio)이 이익이 없는 기업에 사용되는 이유는?', '매출이 이익보다 항상 크기 때문', '이익이 없어 PER 계산이 불가할 때 매출로 상대적 가치를 평가하기 위해', '세금을 포함하기 때문', '부채를 반영하기 때문', 1, '스타트업·성장 초기 기업은 이익이 없거나 마이너스여서 PER 계산이 불가능하므로 매출 기준의 PSR을 활용한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 10, '08', 'PSR', 'PSR = 주가 / 주당매출액에서 PSR이 높다는 것의 의미는?', '저평가 상태이다', '매출 대비 주가가 높게 평가된 상태(고성장 기대 반영)', '매출이 낮다는 뜻이다', '이익이 높다는 뜻이다', 1, 'PSR이 높으면 시장이 해당 기업의 높은 성장 가능성을 기대하여 프리미엄을 부여하고 있다는 의미이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 11, '08', 'PER', '성장주가 가치주보다 PER이 높은 경향이 있는 이유는?', '성장주의 현재 이익이 더 높기 때문', '시장이 미래 이익 성장을 기대하여 현재 높은 가격을 지불하기 때문', '성장주는 배당이 많기 때문', '성장주는 부채가 없기 때문', 1, '성장주는 현재 이익이 낮아도 미래 이익이 빠르게 늘 것으로 기대되므로 투자자들이 높은 PER을 용인한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 12, '08', 'PBR', 'ROE(자기자본이익률)가 높은 기업에 PBR 프리미엄이 부여되는 이유는?', '자산이 많기 때문', '자기자본을 효율적으로 활용하여 높은 이익을 창출하기 때문', '부채가 없기 때문', '매출이 크기 때문', 1, 'PBR과 ROE는 밀접한 관계가 있다. ROE가 높은 기업은 자본 대비 이익 창출 효율이 높아 장부가치 이상의 프리미엄을 받는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 13, '08', '업종별 멀티플', '은행·금융 섹터 평가에 PBR이 적합한 이유는?', '은행은 이익이 없기 때문', '은행 자산(대출·투자)의 장부가가 시장가에 가까워 순자산 기반 평가가 의미 있기 때문', '은행은 EPS를 계산하지 않기 때문', 'PER이 계산되지 않기 때문', 1, '은행·보험은 금융자산이 공정가치로 평가되어 장부가와 시장가의 차이가 작아 PBR 평가가 적합하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 14, '08', 'EV/EBITDA', '부채가 많은 기업에 EV/EBITDA를 사용하는 이유는?', '부채가 있으면 PER을 계산할 수 없기 때문', 'EV는 부채를 포함한 전체 기업 가치를 반영하여 자본구조 차이를 제거할 수 있기 때문', '세금 절감 효과 때문', '이자비용이 EBITDA에 포함되기 때문', 1, 'PER은 주주 가치(시가총액) 기준이지만 EV/EBITDA는 채권자·주주 합산 기업가치(EV)를 기준으로 하여 레버리지 수준이 달라도 비교 가능하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 15, '08', 'PER', 'PEG(PER to Growth) 비율이 투자 판단에 활용되는 이유는?', 'PER만으로는 성장성을 고려하지 못하기 때문', '매출을 직접 반영하기 때문', '부채를 포함하기 때문', '배당수익률을 보정하기 때문', 0, 'PEG = PER / 이익 성장률로 성장성을 감안한 PER 수준을 평가한다. PEG < 1이면 성장 대비 저평가로 간주된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 16, '08', 'BPS', 'BPS(Book Value Per Share) 계산식은?', '순이익 / 발행주식수', '순자산(자본총계) / 발행주식수', '매출액 / 발행주식수', '영업이익 / 발행주식수', 1, 'BPS = 자기자본(순자산) / 발행주식수로 주당 장부가를 나타낸다. PBR = 주가 / BPS이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 17, '08', 'PSR', 'SaaS 기업 평가에 PSR이 자주 쓰이는 이유는?', '이익이 많기 때문', '초기 성장 단계에서 이익이 없거나 작아 PER이 무의미하고 매출 성장이 핵심 가치이기 때문', '자산이 많기 때문', '배당을 주기 때문', 1, 'SaaS 기업은 초기 고성장 시기에 이익보다 매출 성장률이 핵심이어서 매출 기반의 PSR로 밸류에이션을 평가한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 18, '08', '멀티플 평가', '절대적 저PER이 좋은 투자가 아닐 수 있는 이유는?', '이익이 크기 때문', '이익이 줄거나 사업이 쇠퇴하는 경우 PER이 낮게 보여도 실제로는 고평가일 수 있기 때문', '주가가 낮기 때문', '세금이 높기 때문', 1, '시장은 미래를 반영하므로 향후 이익이 감소할 것으로 예상되는 기업의 PER은 현재 숫자가 낮아도 가치 함정일 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 19, '08', 'EPS', 'EPS(Earnings Per Share) 계산식은?', '매출액 / 발행주식수', '당기순이익 / 발행주식수', '영업이익 / 주가', '배당금 / 주가', 1, 'EPS = 당기순이익 / 발행주식수(가중평균)로 주주 1주당 귀속되는 이익을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 20, '08', '티커', 'NYSE에 상장된 주식과 NASDAQ에 상장된 주식의 티커 구분 방법은?', 'NYSE는 3자리, NASDAQ은 4자리', 'NYSE는 1~3자리 알파벳, NASDAQ은 보통 4~5자리 알파벳', '숫자와 알파벳의 혼합 여부로 구분', '구분 불가', 1, '일반적으로 NYSE 상장 종목 티커는 1~3자리(예: T, GM, JPM), NASDAQ 상장 종목은 4~5자리(예: AAPL, GOOG)가 많다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 21, '08', 'PBR', 'IT·소프트웨어 기업이 높은 PBR을 가지는 이유는?', '유형자산이 많기 때문', '브랜드·특허·인적자본 등 무형자산 가치가 장부에 반영되지 않기 때문', '부채가 없기 때문', '배당을 많이 주기 때문', 1, 'IT 기업은 소프트웨어, 특허, 브랜드 등 무형자산이 핵심이지만 장부에 충분히 반영되지 않아 장부가 대비 시장가가 높아 PBR이 크게 나온다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 22, '08', 'EV/EBITDA', 'M&A(기업 인수합병) 시 EV/EBITDA를 활용하는 이유는?', '주가가 없어도 계산되기 때문', '인수 후 자본구조 재편을 반영하는 기업 전체 가치 비교에 적합하기 때문', '감가상각비가 높기 때문', '세금이 없기 때문', 1, 'M&A에서 인수자는 부채도 인수하므로 시가총액이 아닌 EV(기업 전체 가치)와 EBITDA(현금 창출력) 비교가 합리적이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 23, '08', 'PER', '방어주(필수소비재·유틸리티) 섹터의 PER이 상대적으로 낮은 이유는?', '이익이 없기 때문', '이익 성장성이 낮고 경기 방어적 특성으로 성장 프리미엄이 적기 때문', '부채가 많기 때문', '배당이 없기 때문', 1, '필수소비재·유틸리티는 안정적이지만 성장이 느려 높은 성장 프리미엄이 반영되지 않아 성장주 대비 낮은 PER을 보이는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 24, '08', '멀티플 평가', '금리 상승이 주식 PER에 미치는 일반적 영향은?', 'PER 상승', 'PER 하락 압력', 'PER 변화 없음', '배당만 하락', 1, '금리 상승 시 할인율이 높아져 미래 이익의 현재가치가 줄고, 채권 대비 주식 매력도가 낮아져 PER 하락 압력이 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 25, '08', 'PSR', 'PSR이 낮은 산업으로 일반적으로 적절한 것은?', '소프트웨어·플랫폼', '바이오', '유통·저마진 소매업', '반도체 설계', 2, '유통·소매업은 매출은 크지만 순이익률이 낮아 PSR이 낮게 형성된다. PSR 해석은 산업별 수익률 차이를 고려해야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 26, '08', 'PBR', 'ROE와 PBR의 관계를 설명한 것으로 가장 적절한 것은?', '무관하다', 'ROE = PBR × PER의 분해 관계가 있다 (듀폰의 변형)', 'ROE가 낮을수록 PBR이 높다', 'PBR이 높을수록 ROE는 낮아진다', 1, 'ROE = 순이익/자기자본 = (순이익/주가) × (주가/자기자본) = (1/PER) × PBR의 관계로, PBR은 ROE와 PER의 함수이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 27, '08', 'EV/EBITDA', 'EBITDA가 현금 창출력의 근사치로 쓰이는 이유는?', '세금이 포함되기 때문', '감가상각·이자·세금을 제외한 영업 현금흐름에 가까운 지표이기 때문', '매출과 동일하기 때문', '장기 부채를 포함하기 때문', 1, 'EBITDA는 현금 유출이 없는 감가상각과 자본구조·세금 효과를 제거하여 영업에서 창출되는 현금 흐름의 근사값으로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 28, '08', '멀티플 평가', '적정 멀티플보다 낮게 거래될 때 기대되는 투자 전략은?', '매도', '매수 (저평가 매수)', '관망', '공매도', 1, '기업이 업종 적정 멀티플 이하로 거래되면 상대적 저평가로 판단하여 매수 기회로 볼 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 29, '08', 'PER', '희석 EPS(Diluted EPS)와 기본 EPS(Basic EPS)의 차이는?', '동일하다', '희석 EPS는 스톡옵션·전환사채 등 잠재적 주식 발행 효과를 포함하여 계산한다', '기본 EPS가 항상 더 낮다', '희석 EPS는 배당금을 포함한다', 1, '희석 EPS는 스톡옵션, 전환사채 등이 모두 주식으로 전환된 최대 주식 수를 기준으로 계산한 보수적 EPS이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (8, 30, '08', '멀티플 평가', 'PER, PBR, EV/EBITDA, PSR을 활용한 복합 밸류에이션의 장점은?', '단일 지표로도 충분하다', '각 지표의 단점을 보완하고 다각도 분석으로 가치 판단의 신뢰성을 높인다', '계산이 간단해진다', '미래 예측이 필요 없다', 1, '단일 멀티플은 각자의 한계(PER: 이익 변동, PBR: 무형자산 미반영 등)가 있어 여러 지표를 종합하면 더 균형 잡힌 평가가 가능하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 1, '09', '추세분석', '상승 추세선을 올바르게 설명한 것은?', '연속적인 고점을 연결한 선', '연속적인 저점(higher lows)을 연결한 선', '이동평균선 위에 그은 선', '52주 고점들을 연결한 선', 1, '상승 추세선은 차트에서 연속적으로 높아지는 저점(higher lows)들을 연결하여 그리며 지지선 역할을 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 2, '09', '지지/저항', '지지선(Support)이란?', '주가가 상승할 때 저항을 받는 가격대', '주가가 하락하다가 매수세가 유입되어 반등하는 가격대', '52주 신고가 수준', '이동평균선', 1, '지지선은 과거에 주가가 여러 번 하락을 멈추고 반등한 가격대로, 매수세가 집중되는 영역이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 3, '09', '지지/저항', '저항선이 하향 돌파된 후 저항이 지지로 바뀌는 현상은?', '골든크로스', '갭', '역할전환(Role Reversal)', '다이버전스', 2, '역할전환은 과거의 지지선이 저항선으로, 혹은 저항선이 지지선으로 기능이 바뀌는 현상이다. 기술적 분석의 핵심 원리 중 하나이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 4, '09', '이동평균', '단기(MA5)가 장기(MA20)를 위로 교차할 때 나타나는 신호는?', '데드크로스', '골든크로스', '다이버전스', '피보나치 되돌림', 1, '골든크로스는 단기 이동평균선이 장기 이동평균선을 아래에서 위로 교차하는 현상으로 매수 신호로 해석된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 5, '09', '이동평균', '데드크로스(Dead Cross)란?', '단기 MA가 장기 MA를 위로 교차', '단기 MA가 장기 MA를 아래로 교차', '주가가 MA200 위로 상승', '볼린저밴드 수축', 1, '데드크로스는 단기 이동평균이 장기 이동평균을 위에서 아래로 교차하는 현상으로 매도 신호로 해석된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 6, '09', '이동평균', 'MA200(200일 이동평균선)의 의미는?', '단기 모멘텀 지표', '장기 추세를 나타내며 주가의 장기 지지/저항 역할', '거래량 이동평균', '볼린저밴드 중선', 1, 'MA200은 약 1년간의 평균 주가로 장기 추세를 보여주며 기관·장기 투자자들이 중요하게 참고하는 지지/저항선이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 7, '09', 'RSI', 'RSI(상대강도지수)의 기본 계산 기간은?', '5일', '9일', '14일', '20일', 2, 'RSI는 기본적으로 14일을 기준으로 계산하며, 최근 14일간 상승폭 평균과 하락폭 평균의 비율을 이용한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 8, '09', 'RSI', 'RSI가 70 이상일 때 일반적인 의미는?', '과매도 구간', '중립 구간', '과매수 구간', '추세 전환 확정', 2, 'RSI 70 이상은 과매수(Overbought) 구간으로 단기 조정 가능성을 시사한다. 30 이하는 과매도(Oversold) 구간이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 9, '09', 'MACD', 'MACD의 계산 방법은?', 'EMA(12) - EMA(26)', 'EMA(26) - EMA(12)', 'MA(10) × MA(20)', 'RSI(14) - RSI(9)', 0, 'MACD = EMA(12) - EMA(26)으로 단기와 장기 지수이동평균의 차이를 나타내며 추세의 방향과 모멘텀을 분석한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 10, '09', 'MACD', 'MACD 시그널선(Signal Line)이란?', 'MACD 자체', 'MACD의 9일 EMA', '거래량 가중 평균', 'RSI의 이동평균', 1, '시그널선은 MACD의 9일 지수이동평균(EMA)으로, MACD가 시그널선을 상향 돌파하면 매수, 하향 돌파하면 매도 신호로 해석한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 11, '09', '볼린저밴드', '볼린저밴드(Bollinger Bands) 구성은?', '상단밴드, 중간밴드(MA20), 하단밴드', '상단밴드와 하단밴드만', '5일 MA와 20일 MA', 'RSI 70선과 30선', 0, '볼린저밴드는 중간밴드(20일 MA)를 중심으로 표준편차 ±2배 범위의 상단·하단 밴드로 구성된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 12, '09', '볼린저밴드', '볼린저밴드가 좁아지는(수축) 현상의 의미는?', '추세 가속', '변동성 감소, 이후 큰 변동(돌파) 가능성', '과매수 상태', '추세 전환 완료', 1, '볼린저밴드 수축(squeeze)은 변동성이 낮아진 상태로 이후 방향성을 잡고 크게 움직이는 변동성 확대가 임박했음을 시사한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 13, '09', '피보나치', '피보나치 되돌림(Fibonacci Retracement)에서 가장 많이 주목받는 되돌림 비율은?', '50%와 78.6%', '38.2%와 61.8%', '10%와 90%', '25%와 75%', 1, '피보나치 주요 비율은 23.6%, 38.2%, 50%, 61.8%, 78.6%이며 그 중 38.2%와 61.8%가 가장 중요한 지지/저항 수준으로 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 14, '09', '피보나치', '피보나치 61.8% 되돌림이 중요한 이유는?', '황금비(Golden Ratio)에서 파생된 비율로 자연·시장 모두에서 반응이 자주 발생하기 때문', '단순히 계산이 쉽기 때문', '항상 100% 정확하기 때문', '중앙은행이 지정한 비율이기 때문', 0, '61.8%는 피보나치 황금비(1/1.618)에서 유래한 비율로 기술적 분석에서 강한 지지/저항 수준으로 널리 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 15, '09', '갭', '갭(Gap) 중 강한 상승 돌파 후 되돌아오지 않는 유형은?', '소진 갭', '브레이크어웨이 갭', '커먼 갭', '런어웨이 갭', 1, '브레이크어웨이 갭(Breakaway Gap)은 중요 지지/저항 돌파 시 발생하며 강한 추세 시작을 나타내고 메워지지 않는 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 16, '09', '갭', '추세 말미에 나타나며 반전 신호인 갭은?', '브레이크어웨이 갭', '런어웨이 갭', '소진 갭(Exhaustion Gap)', '커먼 갭', 2, '소진 갭은 추세의 마지막 단계에 극도의 매수/매도 심리로 나타나는 갭으로 이후 추세 반전이 자주 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 17, '09', '이동평균', '지수이동평균(EMA)이 단순이동평균(SMA)보다 최근 가격에 더 빠르게 반응하는 이유는?', '계산 기간이 더 짧기 때문', '최근 데이터에 더 높은 가중치를 부여하기 때문', '거래량을 포함하기 때문', '고가와 저가의 평균을 사용하기 때문', 1, 'EMA는 최근 데이터에 기하급수적으로 감소하는 가중치를 부여하므로 SMA보다 최근 가격 변화에 빠르게 반응한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 18, '09', 'RSI', 'RSI 다이버전스(Divergence)란?', '주가와 RSI가 같은 방향으로 움직이는 현상', '주가는 신고가를 갱신하나 RSI는 낮아지는(또는 반대) 현상으로 추세 약화 신호', '볼린저밴드와 MACD의 교차', 'EMA와 SMA의 차이', 1, '강세 다이버전스는 주가 저점이 낮아지나 RSI 저점이 높아지는 경우, 약세 다이버전스는 주가 고점이 높아지나 RSI 고점이 낮아지는 경우이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 19, '09', 'MACD', 'MACD 히스토그램이 0선을 위로 교차할 때의 의미는?', 'MACD가 시그널선을 하향 돌파', 'MACD가 시그널선을 상향 돌파(매수 신호)', '과매수 진입', '추세 종료', 1, 'MACD 히스토그램 = MACD - 시그널선으로 히스토그램이 0 위로 올라오면 MACD가 시그널선을 상향 돌파하여 모멘텀 강화를 의미한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 20, '09', '추세분석', '하락 추세가 진행될 때 나타나는 특징은?', '연속적으로 높아지는 고점과 저점', '연속적으로 낮아지는 고점(lower highs)과 저점(lower lows)', '거래량 지속 증가', '볼린저밴드 수축', 1, '하락 추세는 고점과 저점이 모두 낮아지는(lower highs, lower lows) 패턴으로 식별된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 21, '09', '볼린저밴드', '주가가 볼린저밴드 상단을 돌파하면 일반적으로?', '즉시 하락한다', '강한 상승 모멘텀을 의미하거나 단기 과매수 가능성을 나타낸다', '거래량이 0이 된다', '하단밴드로 즉시 이동한다', 1, '볼린저밴드 상단 돌파는 강한 모멘텀 신호이지만 과매수 영역으로 단기 조정 가능성도 있어 다른 지표와 함께 분석해야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 22, '09', '피보나치', '피보나치 50% 되돌림이 수학적으로는 피보나치 수열에서 유래하지 않음에도 사용되는 이유는?', '계산이 어렵기 때문', '시장 참여자들이 심리적 절반 수준으로 인식하여 실제로 지지/저항이 형성되기 때문', '기관투자자만 사용하기 때문', '공식이 아니라 불필요하다', 1, '50% 되돌림은 엄밀히 피보나치 수열이 아니나 투자자들이 심리적 중간 수준으로 인식하여 지지/저항 효과가 자기실현적으로 나타난다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 23, '09', 'RSI', 'RSI 30 이하에서 매수 신호를 해석할 때 주의해야 할 점은?', 'RSI 30은 절대적 매수 신호이다', '강한 하락 추세에서는 RSI가 30 이하에 오래 머물 수 있어 다른 지표와 병행해야 한다', '항상 즉시 반등한다', 'RSI 30은 과매수이다', 1, '강한 하락 추세에서는 RSI가 과매도 구간에서도 계속 하락할 수 있어 추세 확인 없이 RSI 하나만으로 매수 결정을 내리면 위험하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 24, '09', '추세분석', '채널(Channel)이란?', '단일 추세선', '상단과 하단이 평행한 두 추세선 사이 구간', '볼린저밴드의 다른 이름', '피보나치 구간', 1, '추세 채널은 상승/하락 추세에서 주가가 평행한 두 선 사이에서 움직이는 패턴으로 채널 하단은 지지, 상단은 저항 역할을 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 25, '09', 'MACD', 'MACD가 양(+)에서 음(-)으로 전환될 때 시사하는 것은?', '강한 매수 시점', '상승 모멘텀 약화 및 하락 전환 가능성', '볼린저밴드 수축', '피보나치 되돌림 완료', 1, 'MACD가 0선 아래로 내려오면 단기 EMA가 장기 EMA를 하회하여 하락 모멘텀이 우세해졌음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 26, '09', '이동평균', 'MA5(5일선)의 특징으로 가장 적절한 것은?', '장기 추세를 보여준다', '단기 가격 변동에 민감하여 노이즈가 많다', '1년 평균을 나타낸다', '변동이 거의 없다', 1, 'MA5는 단 5일의 평균이므로 주가 변화에 매우 민감하여 단기 모멘텀을 파악하는 데 쓰이지만 허위 신호(noise)가 많다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 27, '09', '기술적분석', '기술적 분석의 기본 가정이 아닌 것은?', '시장 가격은 모든 정보를 반영한다', '가격은 추세를 이룬다', '역사는 반복된다', '기업 펀더멘털이 주가를 결정한다', 3, '기술적 분석의 3대 가정은 ① 모든 정보가 가격에 반영됨, ② 가격은 추세, ③ 역사는 반복이다. 펀더멘털 분석은 기본적 분석(FA)의 영역이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 28, '09', '볼린저밴드', '볼린저밴드 %B 지표가 1보다 크다는 것의 의미는?', '주가가 중간밴드 아래에 있다', '주가가 상단밴드 위에 있다', '볼린저밴드 수축 중이다', '주가가 하단밴드 아래에 있다', 1, '%B = (주가 - 하단밴드) / (상단밴드 - 하단밴드)로 %B > 1이면 주가가 볼린저밴드 상단을 초과했다는 의미이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 29, '09', '피보나치', '피보나치 확장(Extension) 레벨이 사용되는 상황은?', '되돌림 지지 수준을 찾을 때', '돌파 후 다음 목표 가격을 설정할 때', '지지선이 붕괴될 때', '이동평균 계산 시', 1, '피보나치 확장 레벨(127.2%, 161.8%, 261.8% 등)은 추세가 이전 고점을 돌파한 후 다음 목표 가격을 예측하는 데 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (9, 30, '09', 'RSI', '스토캐스틱(Stochastics) 지표와 RSI의 공통점은?', '계산 기간이 동일하다', '모두 0~100 사이 값을 가지는 오실레이터로 과매수/과매도 판단에 사용된다', '이동평균의 일종이다', '볼린저밴드에서 파생된 지표이다', 1, '스토캐스틱과 RSI는 모두 0~100 범위의 모멘텀 오실레이터로 시장의 과열 또는 침체 여부를 판단하는 데 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 1, '10', '캔들', '캔들차트에서 몸통(Body)은 무엇을 나타내는가?', '당일의 최고가와 최저가 범위', '당일 시가와 종가 사이의 범위', '거래량', '다음날 예상 가격', 1, '캔들 몸통은 시가(Open)와 종가(Close) 사이의 범위를 나타낸다. 종가 > 시가이면 양봉(상승), 종가 < 시가이면 음봉(하락)이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 2, '10', '캔들', '캔들의 꼬리(Wick/Shadow)가 나타내는 것은?', '시가와 종가 사이의 범위', '당일 고가-저가 중 몸통 밖의 가격 범위', '다음날 예상 고가·저가', '이동평균과의 차이', 1, '위꼬리(upper shadow)는 고가에서 몸통(시가·종가 중 높은 쪽)까지, 아래꼬리(lower shadow)는 저가에서 몸통(낮은 쪽)까지의 범위이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 3, '10', '캔들패턴', '도지(Doji) 캔들의 특징은?', '매우 긴 양봉', '시가와 종가가 같거나 거의 같아 몸통이 없는 캔들', '하단 꼬리만 있는 캔들', '거래량이 0인 캔들', 1, '도지는 시가와 종가가 같거나 매우 가까운 캔들로 매수·매도 세력의 균형을 나타내며 추세 전환 가능성을 시사한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 4, '10', '캔들패턴', '망치형(Hammer) 캔들이 강한 매수 신호로 해석되는 이유는?', '긴 위꼬리가 있어서', '하락 추세 말미에 나타나며 긴 아래꼬리가 매도 후 강한 매수세 유입을 나타내기 때문', '몸통이 크기 때문', '거래량이 낮기 때문', 1, '망치형은 하락 추세에서 장중 크게 하락했다가 매수세로 종가가 크게 회복된 형태로 반등 가능성을 시사한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 5, '10', '캔들패턴', '역망치형(Inverted Hammer)과 망치형의 차이는?', '동일하다', '역망치형은 긴 위꼬리를 가지며 하락 추세 말미에 출현한다', '역망치형은 상승 추세에서만 나타난다', '역망치형은 음봉이다', 1, '역망치형은 위꼬리가 길고 하락 추세 말미에 나타나는 잠재적 반전 신호이다. 망치형은 아래꼬리가 길다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 6, '10', '캔들패턴', '교수형(Hanging Man) 캔들이 하락 신호로 해석되는 이유는?', '상승 추세 고점 근처에서 긴 아래꼬리가 매도 압력을 시사하기 때문', '몸통이 크기 때문', '위꼬리가 길기 때문', '도지 캔들이기 때문', 0, '교수형은 상승 추세 말미 고점에서 나타나는 긴 아래꼬리 캔들로, 장중 강한 매도 후 종가가 회복했지만 상승 추세 약화를 경고한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 7, '10', '캔들패턴', '강세 장악형(Bullish Engulfing)이란?', '음봉이 이전 양봉을 완전히 감싸는 패턴', '양봉이 이전 음봉을 완전히 감싸는 패턴', '두 개의 도지 캔들', '갭 상승 후 도지 캔들', 1, '강세 장악형은 이전 음봉의 몸통 전체를 현재 양봉이 완전히 덮는 패턴으로 매수세가 매도세를 압도했음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 8, '10', '캔들패턴', '샛별형(Morning Star) 패턴은 몇 개의 캔들로 구성되는가?', '1개', '2개', '3개', '5개', 2, '샛별형은 음봉 → 작은 몸통(도지 또는 소형봉) → 양봉의 3캔들 패턴으로 하락 추세 반전을 나타내는 강세 패턴이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 9, '10', '차트패턴', '헤드앤숄더(Head & Shoulders) 패턴이 하락 반전 신호인 이유는?', '거래량이 감소하기 때문', '왼쪽 어깨→머리(신고가)→오른쪽 어깨(낮은 고점) 형성 후 목선(neckline) 이탈 시 하락 추세 전환을 나타내기 때문', '이동평균선과 교차하기 때문', 'RSI가 70을 초과하기 때문', 1, '헤드앤숄더는 상승 추세에서 형성되며 머리가 가장 높고 양 어깨가 낮은 형태로 목선을 하향 이탈 시 추세 전환의 확신 신호이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 10, '10', '차트패턴', '이중천장(Double Top) 패턴의 특징은?', '두 번의 저점을 형성 후 상승', '비슷한 수준의 고점 2개 형성 후 목선 이탈로 하락 반전', '완만한 우상향', 'RSI 과매도 후 반등', 1, '이중천장은 비슷한 수준의 고점이 두 번 나타나고 이후 네크라인을 하향 돌파하면 하락 반전으로 해석되는 패턴이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 11, '10', '차트패턴', '이중바닥(Double Bottom) 패턴이 나타내는 것은?', '추가 하락 신호', '비슷한 수준의 저점 2개 형성 후 목선 돌파로 상승 반전', '추세 지속', '과매도 경고만', 1, '이중바닥은 하락 추세에서 비슷한 수준의 저점 두 개가 형성된 후 중간 고점(목선)을 상향 돌파하면 상승 반전 신호이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 12, '10', '차트패턴', '삼각수렴(Triangle) 패턴이 지속 패턴(continuation pattern)으로 분류되는 이유는?', '추세가 역전되기 때문', '기존 추세 방향으로 돌파되는 경우가 많기 때문', '거래량이 증가하기 때문', '이동평균과 관계 없기 때문', 1, '삼각수렴은 고점과 저점이 좁아지며 에너지가 응축되다가 기존 추세 방향으로 돌파되는 경향이 있어 지속 패턴으로 분류된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 13, '10', '차트패턴', '깃발형(Flag) 패턴의 특징은?', '급격한 추세 반전 신호', '강한 추세(폴) 이후 짧은 횡보·조정(깃발) 후 같은 방향으로 돌파하는 지속 패턴', '이중바닥과 동일', '헤드앤숄더의 변형', 1, '깃발형은 급등(폴) → 좁은 횡보(깃발) → 기존 방향 돌파로 구성되는 지속 패턴으로 추세 지속을 시사한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 14, '10', '엘리어트파동', '엘리어트 파동 이론에서 충격파(Impulse Wave)는 몇 개의 파동으로 구성되는가?', '3개', '5개', '7개', '8개', 1, '엘리어트 파동 이론에서 상승 추세의 충격파는 5개 파동(1-2-3-4-5)으로 구성되며, 이후 3파 조정(A-B-C)이 따른다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 15, '10', '엘리어트파동', '엘리어트 파동에서 조정파(Corrective Wave)의 구성은?', '5개 파동', '3개 파동(A-B-C)', '2개 파동', '4개 파동', 1, '엘리어트 파동에서 충격 5파 이후 나타나는 조정파는 A-B-C의 3파동 구조로 이루어진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 16, '10', '엘리어트파동', '엘리어트 파동에서 3파(Wave 3)의 특징은?', '가장 짧은 파동', '일반적으로 5파 중 가장 강하고 긴 상승 파동', '조정 파동', '하락 파동', 1, 'Wave 3는 엘리어트 5파 중 가장 강하고 길게 상승하는 경향이 있으며 "3파는 가장 짧아서는 안 된다"는 규칙이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 17, '10', '캔들패턴', '약세 장악형(Bearish Engulfing)이 출현하기 좋은 위치는?', '하락 추세 바닥', '상승 추세 고점 부근', '횡보 구간 중간', '거래량이 없는 구간', 1, '약세 장악형은 상승 추세의 고점 부근에서 전일 양봉을 완전히 덮는 음봉이 출현하는 패턴으로 하락 반전을 시사한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 18, '10', '차트패턴', '컵앤핸들(Cup and Handle) 패턴이 상승 지속 패턴인 이유는?', '하락 후 급격한 반등이기 때문', '완만한 U자형 되돌림(컵) 후 짧은 조정(핸들)을 거쳐 돌파하는 패턴이기 때문', '헤드앤숄더와 같기 때문', 'RSI가 50을 유지하기 때문', 1, '컵앤핸들은 상승 후 완만한 컵 형태 조정, 짧은 핸들 조정을 거쳐 저항 돌파 시 추가 상승이 예상되는 패턴이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 19, '10', '캔들패턴', '장대 양봉이 강한 매수세를 나타내는 이유는?', '꼬리가 길기 때문', '시가 대비 종가가 크게 상승하여 매수 압력이 강했음을 나타내기 때문', '도지이기 때문', '거래량이 낮기 때문', 1, '장대 양봉은 종가가 시가보다 크게 높아 당일 매수 세력이 강했고 강한 상승 모멘텀이 있음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 20, '10', '차트패턴', '헤드앤숄더 패턴의 목표 하락 폭 계산 방법은?', '무작위로 정한다', '머리(head) 고점에서 목선(neckline)까지의 거리를 목선 이탈 지점에서 아래로 적용', '어깨 폭으로 계산', '피보나치 38.2% 적용', 1, '헤드앤숄더의 목표 하락 폭 = 목선 이탈점 - (머리 고점 - 목선 수준)으로 계산한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 21, '10', '캔들패턴', 'OHLC 캔들에서 O, H, L, C가 나타내는 것은?', '원유, 높이, 낮음, 종가', '시가, 고가, 저가, 종가(Open, High, Low, Close)', '개시, 상한, 하한, 완료', '주문, 보유, 손실, 이익', 1, 'OHLC는 시가(Open), 고가(High), 저가(Low), 종가(Close)를 의미하며 캔들차트의 기본 데이터 구성이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 22, '10', '엘리어트파동', '엘리어트 파동에서 4파(Wave 4)의 규칙은?', '4파는 항상 2파보다 길다', '4파의 저점은 1파의 고점과 겹쳐서는 안 된다', '4파는 상승 파동이다', '4파 후에는 반드시 하락한다', 1, '엘리어트 파동의 핵심 규칙 중 하나는 4파의 저점이 1파의 고점 아래로 내려오면 안 된다는 것이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 23, '10', '차트패턴', '쐐기형(Wedge) 패턴의 하락 쐐기(Falling Wedge)가 나타내는 것은?', '하락 추세 지속', '고점과 저점이 함께 낮아지지만 수렴하며 상승 돌파 가능성', '횡보', '추세 없음', 1, '하락 쐐기는 하락 압력이 약해지면서 고점과 저점이 모두 낮아지지만 수렴하는 형태로 상향 돌파 시 상승 반전 신호이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 24, '10', '캔들패턴', '석별형(Evening Star)은 어떤 신호인가?', '강한 상승 신호', '상승 추세 말미의 하락 반전 신호', '중립 신호', '횡보 지속 신호', 1, '석별형(Evening Star)은 샛별형의 반대로 상승 추세 말미에 나타나는 양봉→작은 몸통→음봉의 3캔들 하락 반전 패턴이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 25, '10', '엘리어트파동', '엘리어트 파동 이론의 주요 한계점은?', '모든 시장에서 완벽하게 적용된다', '파동 구분이 주관적이어서 같은 차트를 보고도 다른 해석이 나올 수 있다', '단기 매매에만 사용된다', '거래량을 무시한다', 1, '엘리어트 파동은 파동의 시작과 끝을 확인하기 전까지 주관적 해석이 필요하여 실시간 적용 시 분석자마다 다른 결론이 나올 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 26, '10', '차트패턴', '역헤드앤숄더(Inverse Head and Shoulders) 패턴이 나타내는 것은?', '하락 반전', '하락 추세에서 상승 반전', '추세 지속', '과매수 경고', 1, '역헤드앤숄더는 헤드앤숄더의 상하 반전 패턴으로 하락 추세 말미에 나타나 상승 반전을 시사하는 패턴이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 27, '10', '캔들패턴', '위꼬리가 매우 긴 슈팅스타(Shooting Star) 캔들의 의미는?', '강한 매수 신호', '상승 추세에서 장중 급등 후 매도세로 종가가 크게 밀려 하락 반전 가능성 시사', '거래량이 낮다', '도지와 동일', 1, '슈팅스타는 상승 추세 고점에서 장중 크게 올랐다가 강한 매도세로 시가 근처로 종가가 하락한 형태로 하락 반전 경고 신호이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 28, '10', '차트패턴', '돌파(Breakout) 확인 시 거래량이 중요한 이유는?', '거래량은 무관하다', '거래량 증가를 동반한 돌파는 신뢰도가 높고 가짜 돌파(false breakout) 가능성이 낮다', '거래량이 낮을수록 확실한 돌파이다', '거래량은 이동평균과 함께 봐야만 한다', 1, '저항선 돌파 시 거래량이 크게 증가하면 많은 참여자가 이를 인식하고 참여한 것으로 신뢰도 높은 돌파로 간주된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 29, '10', '엘리어트파동', '엘리어트 파동과 피보나치 비율의 관계는?', '무관하다', '엘리어트 파동의 각 파동 목표치와 되돌림 수준이 피보나치 비율과 일치하는 경향이 있다', '피보나치는 엘리어트 이후에 개발됐다', '엘리어트 파동은 피보나치를 사용하지 않는다', 1, '엘리어트 파동의 각 파동 비율(예: 2파는 1파의 61.8% 되돌림, 3파는 1파의 161.8% 확장)이 피보나치 비율과 밀접하게 연관된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (10, 30, '10', '캔들패턴', '갭 상승 후 작은 몸통, 이후 갭 하락 음봉이 나타나는 저녁별(Evening Star)에서 중간 캔들의 역할은?', '추세를 확정하는 역할', '매수·매도 균형이 무너지고 있음을 나타내는 전환 준비 단계', '보조 신호 없음', '거래량 지표 역할', 1, '석별형 중간 캔들은 매수세와 매도세가 팽팽하게 대립하는 단계로 다음날 큰 음봉이 나타나면 하락 반전이 확인된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 1, '11', '주주 권리', '주주의 3대 권리가 올바르게 묶인 것은?', '경제적 권리, 경영 참여 권리, 정보 접근 권리', '배당권, 의결권, 환불권', '양도권, 분할권, 소각권', '설립권, 해산권, 청산권', 0, '주주의 3대 권리는 경제적 권리(배당, 잔여재산 분배), 경영 참여 권리(의결권, 주주제안권), 정보 접근 권리(재무제표 열람 등)이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 2, '11', '자사주', '자사주 소각의 주주가치 제고 효과는?', '총 자산 증가', '유통 주식수 감소 → EPS 증가 → 주당 가치 상승', '부채 감소', '매출 증가', 1, '자사주 소각은 발행 주식수를 영구적으로 줄여 EPS(주당순이익)를 높이고 주주 1인당 가치를 증가시키는 효과가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 3, '11', '주주제안권', '소수주주가 주주제안권을 행사하기 위한 요건은?', '지분 0.1% 이상, 보유 기간 무관', '지분 1% 이상, 6개월 이상 보유', '지분 5% 이상, 1년 이상 보유', '단 1주 보유시도 가능', 1, '주주제안권은 발행주식 총수의 1% 이상을 6개월 이상 보유한 주주가 주주총회 안건을 제안할 수 있는 권리이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 4, '11', '거래소', 'KOSPI, KOSDAQ, KONEX의 설명이 올바르게 짝지어진 것은?', 'KOSPI: 중소기업 전용, KOSDAQ: 대기업 전용, KONEX: 기술기업', 'KOSPI: 대기업 중심 주시장, KOSDAQ: 기술·벤처 중심, KONEX: 초기 중소·벤처기업', 'KOSPI: 코스닥과 동일, KONEX: 외국인 전용', 'KOSDAQ: 국채 시장, KONEX: 파생상품 시장', 1, 'KOSPI는 대기업 중심의 주시장, KOSDAQ은 기술·벤처 기업 중심, KONEX는 초기 중소·벤처기업을 위한 시장이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 5, '11', 'IPO', 'IPO(Initial Public Offering) 절차에서 수요예측(Book Building)의 목적은?', '공모가를 무작위로 설정하기 위해', '기관투자자 수요 조사를 통해 적정 공모가를 결정하기 위해', '소액투자자를 위한 배정', '청약 경쟁률을 높이기 위해', 1, '수요예측은 기관투자자들의 청약 희망 가격과 수량을 수집하여 공모가를 결정하는 과정이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 6, '11', 'IPO', '"따상"의 의미는?', '공모가의 2배로 상장 후 당일 하한가', '상장 첫날 공모가의 2배로 시초가 형성 후 상한가(+30%) 기록', '공모가보다 낮게 시초가 형성', '상장 후 3일 연속 상한가', 1, '"따상"은 시초가가 공모가의 2배로 결정(따)된 후 당일 추가 상한가(상)를 달성하는 것으로 공모가 대비 약 2.6배 수익이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 7, '11', '주문유형', '시장가 주문(Market Order)의 특징은?', '지정한 가격 이하에서만 체결', '현재 시장 최우선 매도(매수)호가로 즉시 체결', '체결이 보장되지 않음', '조건을 걸어 일부만 체결', 1, '시장가 주문은 가격을 지정하지 않고 현재 시장에서 즉시 체결 가능한 최우선 가격으로 전량 체결을 목표로 하는 주문이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 8, '11', '주문유형', '지정가 주문(Limit Order)의 특징은?', '즉시 체결됨', '투자자가 지정한 가격 또는 그 이하(매수)에서만 체결', '가격과 무관하게 체결', '장 마감에만 사용 가능', 1, '지정가 주문은 원하는 가격을 명시하여 해당 가격 이하(매수) 또는 이상(매도)에서만 체결되므로 가격 통제가 가능하지만 즉시 체결을 보장하지 않는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 9, '11', '주문유형', 'IOC(Immediate or Cancel) 주문이란?', '전량 체결이 안 되면 전부 취소', '즉시 체결 가능한 수량은 체결하고 나머지는 취소', '장 시작 시에만 유효', '종가에만 체결', 1, 'IOC 주문은 접수 즉시 체결 가능한 수량은 체결하고 미체결 잔량은 자동 취소되는 주문 유형이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 10, '11', '주문유형', 'FOK(Fill or Kill) 주문이란?', '즉시 체결 가능한 수량만 체결', '전량 즉시 체결이 안 되면 전부 취소', '지정 시간에만 체결', '1주씩만 체결', 1, 'FOK 주문은 전량이 즉시 체결되지 않으면 주문 전체를 취소하는 유형으로 대량 거래 시 부분 체결을 원치 않을 때 사용한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 11, '11', '결제', '한국 주식시장에서 매매 후 실제 결제(대금·주식 인도)가 이루어지는 시점은?', '당일(T+0)', '매매 다음날(T+1)', '매매 후 2일(T+2)', '매매 후 3일(T+3)', 2, '한국 주식시장은 T+2 결제 방식으로 매매 체결일로부터 2 영업일 후에 대금과 주식이 실제로 결제된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 12, '11', '거래비용', '주식 매매 시 부과되는 거래세(증권거래세)의 특징은?', '매수 시 부과됨', '매도 시 매도금액의 일정 비율로 부과됨', '이익이 발생할 때만 부과됨', '연간 1회 부과됨', 1, '증권거래세는 주식을 매도할 때 매도금액의 일정 비율(코스피 0%, 코스닥 0.2% 등)로 부과된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 13, '11', '거래비용', '증권사 수수료(브로커리지)의 부과 시점은?', '이익 발생 시에만', '매수와 매도 모두에 부과됨', '매도 시에만', '연간 계약으로 일괄 청구', 1, '증권사 거래 수수료는 매수·매도 거래가 체결될 때마다 각각 부과되며 온라인은 오프라인보다 낮은 수준이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 14, '11', 'IPO', 'IPO 청약에서 균등 배정 방식이란?', '청약 수량에 비례하여 배정', '청약자 수로 공모주를 균등하게 나누는 방식', '기관에게만 배정', '시가총액 비례 배정', 1, '균등 배정은 청약자들에게 동일한 수의 공모주를 배정하는 방식으로 소액 투자자도 동등하게 청약 기회를 가진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 15, '11', '주식 권리', '배당기준일의 의미는?', '배당금을 실제로 지급하는 날', '이 날 주주명부에 등재된 주주에게 배당권이 부여되는 날', '배당 공시 발표일', '배당 결의일', 1, '배당기준일은 배당을 받을 권리가 확정되는 날로 이 날 주주명부에 등재되어 있어야 배당을 받을 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 16, '11', '주식 권리', '주식 액면분할(Stock Split)이 주주에게 미치는 직접적 효과는?', '주주 수익이 자동으로 증가한다', '주식 수는 늘고 주가는 분할 비율만큼 낮아지지만 총 가치는 동일하다', '배당이 자동으로 늘어난다', '기업 자산이 증가한다', 1, '주식 분할은 1주를 여러 주로 나누어 주가를 낮추고 유동성을 높이지만 주주의 전체 지분 가치는 변하지 않는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 17, '11', '거래소', 'K-OTC 시장의 특징은?', '코스피 상장 기업만 거래', '비상장 주식을 거래하는 장외주식 시장', '파생상품 전문 시장', '국채 전용 시장', 1, 'K-OTC는 금융투자협회가 운영하는 장외주식 거래 시장으로 비상장 기업의 주식을 거래한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 18, '11', 'IPO', 'IPO에서 주관사(underwriter)의 역할은?', '주식을 직접 매수하여 보유', '상장 절차 주관, 공모가 결정, 투자자 모집 주선', '기업 경영에 참여', '정부를 대신하여 심사', 1, '주관사(인수기관)는 IPO 전반을 주관하고 공모가 결정, 수요예측, 청약 주선, 안정적 상장을 지원하는 역할을 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 19, '11', '주문유형', '조건부 지정가 주문(Conditional Limit Order)이란?', '항상 시장가로 체결', '지정가로 접수하되 장 마감 전 미체결 시 시장가로 전환', '일정 조건 충족 시 취소', '예약 주문 방식', 1, '조건부 지정가 주문은 일반 시간에는 지정가로 주문을 내고 장 마감 전까지 미체결이면 시장가로 전환되어 체결을 최우선으로 하는 방식이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 20, '11', '주식 권리', '우선주와 보통주의 차이는?', '동일하다', '우선주는 배당·잔여재산 분배에서 우선권을 갖지만 의결권이 없거나 제한된다', '우선주는 더 높은 의결권을 갖는다', '우선주는 상장 불가', 1, '우선주는 배당과 청산 시 잔여재산 배분에서 우선권을 갖는 대신 의결권이 없거나 제한된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 21, '11', 'IPO', '상장 후 보호예수(Lock-up) 기간의 목적은?', '주가를 올리기 위해', '대주주·기관투자자가 일정 기간 주식을 매도하지 못하게 하여 상장 초기 물량 급증을 방지', '배당을 제한하기 위해', '공모가를 유지하기 위해', 1, '보호예수는 상장 초기에 대주주나 기관의 대량 매도로 주가가 급락하는 것을 방지하기 위해 일정 기간 매도를 제한하는 제도이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 22, '11', '거래비용', '슬리피지(Slippage)란?', '증권사 수수료', '원하는 주문 가격과 실제 체결 가격의 차이', '증권거래세', '환전 수수료', 1, '슬리피지는 주문 시 예상한 가격과 실제 체결된 가격 간의 차이로 유동성이 낮거나 시장이 빠르게 움직일 때 크게 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 23, '11', '주주 권리', '집중투표제(Cumulative Voting)의 목적은?', '대주주의 의결권 강화', '소수주주가 이사 선임에서 지분에 비례한 의결권을 집중시켜 소수주주 대표 이사를 선임할 수 있는 제도', '배당 우선권 부여', '감사 선임 제한', 1, '집중투표제에서 소수주주는 이사 수 × 보유주식 수만큼의 의결권을 특정 후보에 몰아줄 수 있어 소수주주의 이사회 진입을 가능하게 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 24, '11', '거래소', 'KOSDAQ 상장 기업의 일반적 특징은?', '시가총액 1위 기업들이 모두 여기에 있다', '기술·벤처 기업 중심으로 상대적으로 소형·성장 기업이 많다', '국채만 거래한다', '외국 기업만 상장 가능하다', 1, 'KOSDAQ은 IT, 바이오, 게임 등 기술·벤처 기업 중심의 시장으로 상대적으로 소규모 성장 기업이 많고 변동성이 높다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 25, '11', 'IPO', '스팩(SPAC: Special Purpose Acquisition Company)이란?', '일반 기업과 동일한 IPO', '인수합병을 목적으로 상장된 페이퍼 컴퍼니로 비상장기업과 합병하여 우회상장시키는 수단', '국채 전용 상장 수단', '공모펀드의 일종', 1, 'SPAC은 자금 조달을 위해 상장한 빈 회사(blank check company)로 비상장기업이 SPAC과 합병하여 상장 절차 없이 우회 상장하는 방법이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 26, '11', '주식 권리', '주식 배당(Stock Dividend)이 현금 배당과 다른 점은?', '세금이 부과되지 않는다', '현금 대신 주식으로 배당하여 주식 수가 늘고 현금 유출이 없다', '주주의 전체 가치가 증가한다', '배당을 받지 못한다', 1, '주식 배당은 현금 대신 신주를 배정하므로 기업의 현금 유출 없이 배당하는 방법이다. 주주의 전체 가치는 이론적으로 변하지 않는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 27, '11', '거래비용', '비용 면에서 ETF가 개별 주식 매매보다 불리한 점은?', 'ETF는 수수료가 없다', 'ETF는 운용보수(총보수)가 매년 부과되며 매매 시 스프레드 비용이 있다', 'ETF는 세금이 더 높다', 'ETF는 거래량이 없다', 1, 'ETF는 매매 수수료 외에 운용보수(TER)가 매일 조금씩 차감되고 매매 시 괴리율과 스프레드도 비용 요인이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 28, '11', '주문유형', '스탑로스(Stop-Loss) 주문이란?', '이익을 확정하기 위한 주문', '지정한 손절 가격에 도달하면 자동으로 매도되는 리스크 관리 주문', '종가에만 체결되는 주문', '배당 지급 후 자동 매도', 1, '스탑로스 주문은 보유 주식이 지정 가격 이하로 하락하면 자동으로 매도 주문이 발동되어 손실을 제한하는 리스크 관리 도구이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 29, '11', 'IPO', 'Green Shoe Option(초과배정옵션)의 목적은?', '공모주를 더 많이 팔기 위해', '상장 후 주가 안정을 위해 주관사가 추가로 주식을 매입·매도할 수 있는 권리', '청약 환불 옵션', '대주주 지분 보호', 1, 'Green Shoe Option은 공모 후 주가가 하락할 경우 주관사가 시장에서 주식을 매입하여 주가를 지지하는 안정화 장치이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (11, 30, '11', '주식 권리', '주주가 신주인수권(Preemptive Right)을 갖는 이유는?', '배당을 더 받기 위해', '유상증자 시 기존 주주의 지분율이 희석되는 것을 방지하기 위해', '의결권을 강화하기 위해', '배당기준일을 정하기 위해', 1, '신주인수권은 유상증자 시 기존 주주가 지분 비율에 따라 신주를 우선 청약할 수 있는 권리로 지분 희석을 방지한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 1, '12', '금융투자상품', '자본시장법상 금융투자상품의 핵심 정의 요소는?', '원금이 보장된다', '원금 손실 가능성이 있는 투자 계약', '이자가 발생한다', '정부가 보증한다', 1, '자본시장법은 투자원금 손실 가능성이 있는 금융상품을 금융투자상품으로 정의한다. 원금 보장 상품은 금융투자상품에 해당하지 않는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 2, '12', '금융투자상품', '자본시장법상 증권과 파생상품의 주요 차이는?', '동일하다', '증권은 원금 초과 손실이 없으나 파생상품은 원금 초과 손실이 가능하다', '파생상품은 주식만 포함', '증권은 손실이 없다', 1, '자본시장법은 증권(지분증권, 채무증권 등)과 파생상품(선물, 옵션, 스왑)을 구분하며 파생상품은 원금 초과 손실 가능성이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 3, '12', 'ETF 구조', 'ETF(Exchange Traded Fund)의 주요 특징은?', '거래소에서 거래 불가', '증권거래소에 상장되어 주식처럼 실시간 매매 가능한 펀드', '원금 보장 상품', '특정 기업의 주식만 담음', 1, 'ETF는 인덱스나 특정 자산을 추종하며 거래소에 상장되어 주식처럼 실시간으로 매매할 수 있는 펀드이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 4, '12', '펀드 구조', '개방형 펀드(Open-End Fund)의 특징은?', '설정액이 고정되어 있어 추가 매수 불가', '언제든지 추가 설정(매수)과 환매(매도)가 가능', '거래소에서만 매매', '만기가 고정됨', 1, '개방형 펀드는 투자자가 원할 때 수시로 가입(추가 설정)하거나 환매할 수 있어 설정액이 변동된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 5, '12', '펀드 클래스', '펀드 클래스 A와 C의 차이는?', '동일하다', 'A클래스는 선취판매수수료가 있고 C클래스는 없지만 연간 판매보수가 더 높다', 'C클래스는 외국인 전용', 'A클래스만 기관투자자 대상', 1, 'A클래스는 가입 시 선취수수료를 내는 대신 연간 판매보수가 낮고, C클래스는 선취수수료 없이 연간 판매보수가 상대적으로 높다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 6, '12', '펀드 클래스', '펀드 클래스 E(Ae, Ce)의 특징은?', '기관 전용', '온라인(인터넷) 전용 클래스로 판매보수가 낮다', '해외 투자 전용', '원금 보장', 1, 'e클래스는 온라인(인터넷) 채널을 통해 가입하는 클래스로 오프라인 대비 판매 비용이 낮아 투자자에게 유리하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 7, '12', '펀드 클래스', '펀드 클래스 I(기관형)의 특징은?', '개인투자자 전용', '기관투자자 또는 거액 투자자 대상으로 보수가 낮다', '주식 외 투자 불가', '선취수수료만 있다', 1, 'I클래스(기관형)는 대규모 기관투자자나 거액 투자자를 위한 클래스로 운용보수와 판매보수가 일반 개인 클래스보다 낮다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 8, '12', 'EPS', 'EPS(Earnings Per Share) 계산에 필요한 요소는?', '매출액과 발행주식수', '당기순이익과 발행주식수(가중평균)', '영업이익과 배당금', '매출총이익과 시가총액', 1, 'EPS = 당기순이익 / 가중평균 발행주식수로 주당 이익을 나타내며 PER 계산의 기초가 된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 9, '12', 'BPS', 'BPS(Book Value Per Share) 계산식은?', '순이익 / 발행주식수', '자기자본(순자산) / 발행주식수', '매출액 / 주가', '배당금 / 발행주식수', 1, 'BPS = 자기자본(순자산) / 발행주식수로 주당 순자산가치이며 PBR = 주가/BPS 계산에 사용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 10, '12', 'KOSPI', 'KOSPI(Korea Composite Stock Price Index)의 특징은?', '기술 스타트업 전문 시장', '유가증권시장(주식시장)의 대표 지수로 삼성전자 등 대기업이 포함', '파생상품 지수', '채권 지수', 1, 'KOSPI는 한국거래소 유가증권시장의 전체 종목을 시가총액 가중 방식으로 산출한 대표 주가지수이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 11, '12', 'KOSDAQ', 'KOSDAQ 지수의 특징은?', '대기업 중심', '코스닥 시장 상장 종목(주로 중소·기술·바이오) 기반의 주가지수', '채권 포함', '외국 주식 포함', 1, 'KOSDAQ 지수는 코스닥 시장의 전체 상장종목을 대상으로 산출하며 IT, 바이오, 게임 등 기술 기업 비중이 높다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 12, '12', 'NASDAQ', 'NASDAQ 시장의 특징은?', '제조업 중심', '기술·IT 기업 중심의 미국 전자주식시장으로 애플·구글 등이 상장', '채권 전용 시장', '정부 보증 시장', 1, 'NASDAQ은 기술·IT 기업 중심의 미국 전자거래 주식시장으로 AAPL, GOOGL, AMZN 등 주요 기술기업이 상장되어 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 13, '12', 'ETF 구조', 'ETF의 순자산가치(NAV)와 시장가격의 차이를 무엇이라 하는가?', '추적오차', '괴리율', '총보수', '수익률', 1, '괴리율은 ETF의 시장 거래가격과 순자산가치(NAV) 간의 차이 비율로 ETF 매매 효율성을 평가하는 지표이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 14, '12', '펀드 구조', '펀드의 수익자(beneficiary)는?', '자산운용사', '판매사', '수탁사', '펀드에 투자한 투자자', 3, '펀드의 수익자는 펀드에 투자하여 수익증권을 보유한 투자자로 운용 성과에 따른 이익을 귀속받는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 15, '12', '금융투자상품', '채무증권(채권)의 특징은?', '원금이 반환되지 않는다', '발행자가 원금과 이자를 약정하여 상환할 의무를 지는 증권', '주식과 동일한 권리 제공', '의결권 포함', 1, '채무증권(채권)은 발행자가 일정 기간 후 원금을 상환하고 그 기간 동안 이자를 지급할 의무를 가진 확정이자부 증권이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 16, '12', '펀드 구조', '자산운용사, 수탁사, 판매사의 역할이 올바르게 짝지어진 것은?', '운용사: 자산 보관, 수탁사: 운용 결정, 판매사: 투자자 모집', '운용사: 투자 결정, 수탁사: 자산 보관, 판매사: 투자자 모집', '운용사: 투자자 모집, 수탁사: 수익 배분, 판매사: 운용 결정', '모두 동일한 역할', 1, '자산운용사는 투자 결정, 수탁사(신탁업자)는 자산 보관·확인, 판매사는 투자자 모집 및 판매를 담당하는 역할 분리 구조이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 17, '12', 'ETF 구조', 'ETF의 설정(creation)과 환매(redemption) 메커니즘에서 AP(Authorized Participant)의 역할은?', '일반 개인투자자', '시장조성자로 현물 바스켓과 ETF 좌수를 교환하며 괴리율을 좁히는 역할', '자산운용사 직원', '규제기관', 1, 'AP는 ETF 설정·환매 시 기초 자산 바스켓과 ETF 좌수를 교환하는 공인 참가자로 재정거래를 통해 ETF 괴리율을 최소화한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 18, '12', '펀드 클래스', '펀드 클래스 W의 특징은?', '원금 보장형', '온라인 랩(Wrap)이나 ISA 전용으로 보수 체계가 다르다', '해외 투자 전용', '기관 전용', 1, 'W클래스는 wrap account나 ISA 등 특정 채널 또는 계좌 유형 전용 클래스로 해당 채널의 보수 체계를 적용한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 19, '12', '금융투자상품', '집합투자증권(펀드 수익증권)의 특징은?', '원금 보장', '다수 투자자 자금을 모아 운용하는 집합투자기구의 지분을 나타내는 증권', '주식과 동일한 의결권', '발행자가 원리금 상환 의무', 1, '집합투자증권(수익증권)은 다수 투자자의 자금을 모아 운용하는 펀드의 지분으로 운용 성과에 따라 수익이 달라지며 원금 보장이 없다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 20, '12', 'ETF 구조', '레버리지 ETF(2x)의 특징과 주의사항은?', '원금 보장이 된다', '기초지수 일일 수익률의 2배를 추구하며 장기 보유 시 복리 효과로 실제 수익이 기대와 다를 수 있다', '매일 배당을 지급한다', '원금 초과 손실이 불가능하다', 1, '레버리지 ETF는 일일 목표 배수를 달성하도록 설계되어 있어 변동성이 높은 시장에서 장기 보유 시 경로 의존성(beta slippage)으로 성과가 저하될 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 21, '12', '펀드 구조', '펀드 환매 시 기준가격(NAV)이 결정되는 방식은?', '주문 시점의 실시간 가격', '환매 신청 다음 날 또는 그 이후 산출된 기준가격(미래가격제)', '직전 거래일 종가', '매수 시점 가격', 1, '국내 일반 펀드는 미래가격제를 채택하여 환매 신청 이후 기준가격이 산출되어 적용되므로 신청 시점에 가격을 알 수 없다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 22, '12', 'ETF 구조', '인버스 ETF의 특징은?', '지수 상승 시 수익 발생', '기초지수 하락 시 수익이 발생하도록 설계된 역방향 ETF', '채권에만 투자', '원금 보장', 1, '인버스 ETF는 기초지수와 반대 방향으로 수익이 발생하도록 파생상품을 이용하여 운용하며 하락 헤지나 하락장 투자에 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 23, '12', '펀드 클래스', '펀드 클래스 S(신탁형)의 특징은?', '온라인 전용', '은행 신탁을 통해 판매되는 클래스', '기관투자자 전용', '원금 보장', 1, 'S클래스는 은행의 신탁 채널을 통해 판매되는 펀드 클래스로 판매 채널의 특성에 따라 보수가 설정된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 24, '12', '금융투자상품', '파생결합증권(ELS, DLS 등)의 특징은?', '주식과 동일한 구조', '기초자산(주가, 지수 등) 성과에 연계하여 수익이 결정되는 복합 금융상품', '원금 보장', '이자가 항상 확정', 1, '파생결합증권은 기초자산의 가격 변동에 연계되어 수익이 결정되며 원금 손실 위험이 있는 복합 구조 금융상품이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 25, '12', 'ETF 구조', '실물형 ETF와 합성(Synthetic) ETF의 차이는?', '동일하다', '실물형은 기초자산을 직접 보유하고 합성형은 스왑 등 파생계약으로 성과를 복제한다', '합성형만 거래소에 상장', '실물형은 원금 보장', 1, '실물형 ETF는 기초자산을 직접 매입하고, 합성 ETF는 스왑·파생계약을 통해 수익률을 복제하는 방식으로 거래상대방 리스크가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 26, '12', '펀드 구조', '수익증권의 기준가격(NAV per unit)이 1,000원에서 시작하는 이유는?', '임의로 설정됨', '새 펀드 설정 시 기준가격이 1,000원으로 시작하여 운용 성과에 따라 변동됨', '정부가 정한 규정', '투자원금이 1,000원이기 때문', 1, '펀드 설정 시 기준가격 1,000원(1좌당)으로 시작하고 이후 운용 성과(수익·손실)에 따라 기준가격이 변동된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 27, '12', '금융투자상품', '지분증권(주식)의 특징으로 올바른 것은?', '발행자가 원금 상환 의무를 가짐', '기업의 소유권을 나타내며 의결권과 배당청구권을 포함', '원금 보장', '이자가 확정적으로 지급', 1, '지분증권(주식)은 기업에 대한 소유 지분을 나타내며 의결권, 배당청구권, 잔여재산청구권을 부여하지만 원금 보장은 없다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 28, '12', 'ETF 구조', 'ETF의 총보수(TER)가 낮을수록 투자자에게 유리한 이유는?', '수익률이 자동으로 높아지기 때문', '보수는 NAV에서 매일 차감되므로 보수가 낮을수록 순수익률이 높아지기 때문', '거래량이 증가하기 때문', '괴리율이 낮아지기 때문', 1, 'ETF 총보수(운용보수+판매보수+수탁보수 등)는 매일 NAV에서 조금씩 차감되므로 낮을수록 장기 투자자에게 유리하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 29, '12', '펀드 클래스', '펀드 클래스 P(플랫폼형)의 특징은?', '기관 전용', '핀테크·온라인 플랫폼을 통해 판매되며 비용이 낮다', '원금 보장', '해외 전용', 1, 'P클래스는 온라인 투자 플랫폼을 통해 판매되는 클래스로 유통 비용이 낮아 개인 투자자에게 유리한 보수 구조를 갖는다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (12, 30, '12', '금융투자상품', '투자자 적합성(suitability) 원칙이란?', '투자자가 원하는 상품을 무조건 판매하는 원칙', '금융회사가 투자자의 위험 성향과 투자 목적에 맞는 상품만을 권유해야 하는 원칙', '원금 보장을 의미함', '수수료가 없어야 한다는 원칙', 1, '자본시장법상 적합성 원칙은 금융투자업자가 투자자의 투자 목적, 재산 상황, 투자 경험 등에 비추어 적합하지 않은 금융투자상품을 권유해서는 안 된다는 규정이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 1, '13', 'ETF vs 펀드', 'ETF와 일반 펀드의 가장 큰 거래 방식의 차이는?', '동일하다', 'ETF는 거래소에서 실시간 매매, 일반 펀드는 운용사·판매사 경유 기준가로 매매', 'ETF는 기관만 거래 가능', '일반 펀드가 더 낮은 비용', 1, 'ETF는 주식처럼 거래소에서 실시간으로 매매되고, 일반 펀드는 판매사를 통해 기준가(NAV)로 다음날 처리된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 2, '13', 'ETF vs 펀드', '일반 공모펀드 대비 ETF의 비용 측면 장점은?', 'ETF는 항상 무료', '보통 ETF의 총보수(TER)가 동일 유형의 일반 펀드보다 낮다', 'ETF는 세금이 없다', 'ETF는 판매사 수수료만 있다', 1, 'ETF는 패시브 운용이 많고 구조적으로 비용이 낮아 일반 공모펀드 대비 총보수가 낮은 경향이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 3, '13', '괴리율', '괴리율(Premium/Discount)의 계산식은?', '(NAV - 시장가격) / NAV × 100', '(시장가격 - NAV) / NAV × 100', '추적오차 / NAV', '총보수 / NAV', 1, '괴리율 = (ETF 시장가격 - NAV) / NAV × 100으로 양수면 시장가가 NAV보다 높은 프리미엄, 음수면 디스카운트 상태이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 4, '13', '괴리율', '괴리율이 크게 벌어지는 주요 원인은?', '수익률이 높기 때문', '거래량 부족이나 기초자산 시장 휴장 시 가격 발견이 어렵기 때문', '총보수가 낮기 때문', '상장폐지 임박', 1, '해외 자산 ETF에서 기초자산 시장이 휴장 중이거나 유동성이 부족할 때 괴리율이 크게 벌어질 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 5, '13', '추적오차', '추적오차(Tracking Error)란?', 'ETF 시장가격과 NAV의 차이', 'ETF 수익률과 기초지수 수익률의 차이', '총보수의 다른 표현', '배당수익률', 1, '추적오차는 ETF가 목표로 하는 기초지수 수익률과 실제 ETF 수익률 간의 차이를 나타내며 작을수록 지수를 잘 복제하고 있다는 의미이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 6, '13', '추적오차', '추적오차가 발생하는 주요 원인이 아닌 것은?', '운용보수 차감', '포트폴리오 리밸런싱 비용', '배당금 재투자 타이밍 차이', '기초지수 편입 종목 수', 3, '추적오차의 주요 원인은 운용보수, 거래비용, 배당 재투자 타이밍, 지수 리밸런싱 비용 등이다. 기초지수 편입 종목 수 자체는 직접적 원인이 아니다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 7, '13', 'ETF vs 펀드', 'ETF의 투명성(transparency) 장점은?', '보유 자산을 1년에 1회만 공개', '기초자산 포트폴리오가 매일 공시되어 투자자가 무엇에 투자되는지 확인 가능', '운용 전략을 비공개로 유지', '운용사만 접근 가능', 1, 'ETF는 보유 포트폴리오(PDF)를 매일 공시하여 투자자가 실시간으로 투자 내역을 확인할 수 있다는 투명성 장점이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 8, '13', 'ETF vs 펀드', '일반 공모펀드가 ETF보다 유리한 경우는?', '비용이 항상 낮을 때', '액티브 운용으로 초과 수익을 추구하거나 복잡한 전략 구사가 필요한 경우', 'ETF보다 항상 수익이 높을 때', '거래소 상장이 가능할 때', 1, '전문 펀드매니저의 재량 운용이나 특수 전략이 필요한 경우 액티브 펀드(일반 공모펀드)가 ETF보다 유리할 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 9, '13', '일평균거래대금', 'ETF 투자 시 일평균거래대금(ADTV)이 중요한 이유는?', '수익률을 나타내기 때문', '거래대금이 낮은 ETF는 매매 시 원하는 가격에 체결이 어렵고 괴리율이 커질 수 있기 때문', '총보수와 동일하기 때문', 'NAV와 같기 때문', 1, '일평균거래대금이 낮은 ETF는 유동성이 부족하여 매수·매도 시 원하는 가격에 체결되지 않을 수 있고 스프레드도 크다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 10, '13', '계좌 선택', 'ISA(개인종합자산관리계좌)에서 ETF 투자 시 주요 세제 혜택은?', '세금이 없다', '계좌 내 운용 수익에 대해 200만원(서민형 400만원) 비과세, 초과분 9.9% 분리과세', '배당이 100% 비과세', '거래세가 면제된다', 1, 'ISA는 계좌 내 수익을 200만원(일반형) 또는 400만원(서민·청년형)까지 비과세하고 초과분은 9.9% 분리과세하는 세제 혜택이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 11, '13', '계좌 선택', '연금저축계좌에서 ETF 투자의 세제 혜택은?', '세금이 없다', '납입액 연 600만원 한도 세액공제(16.5%), 운용수익 과세 이연', '배당 100% 비과세', '원금 보장', 1, '연금저축은 연간 납입액 600만원(퇴직연금 합산 900만원)까지 최대 16.5% 세액공제를 받고, 운용 중 수익에 대한 과세가 이연된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 12, '13', 'ETF vs 펀드', '액티브 ETF와 패시브 ETF의 차이는?', '동일하다', '패시브는 지수를 그대로 복제하고, 액티브는 펀드매니저가 지수 대비 초과 수익을 추구한다', '액티브 ETF는 원금 보장', '패시브 ETF만 거래소에 상장', 1, '패시브 ETF는 기초지수를 그대로 추종하고, 액티브 ETF는 운용자의 재량으로 포트폴리오를 구성하여 벤치마크 초과 수익을 목표로 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 13, '13', '괴리율', '투자자가 ETF를 NAV 대비 높은 가격에 매수했을 때 발생하는 불이익은?', '이익이 더 많아진다', '기초자산 수익률 대비 실제 투자 수익률이 낮아진다', '세금이 증가한다', '총보수가 오른다', 1, 'NAV보다 높은 가격(프리미엄)에 매수하면 기초지수 수익률보다 낮은 실제 수익률을 얻게 되어 불이익이 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 14, '13', '추적오차', '추적오차가 낮은 ETF가 선호되는 이유는?', '수익률이 항상 높기 때문', '기초지수를 충실히 복제하여 투자자가 기대한 성과에 가깝게 운용됨을 의미하기 때문', '비용이 없기 때문', '원금이 보장되기 때문', 1, '추적오차가 낮을수록 ETF가 기초지수의 수익률을 정확하게 복제하고 있어 투자자가 의도한 노출(exposure)을 얻을 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 15, '13', 'ETF vs 펀드', 'ETF 매매 시 증권사 수수료 외 추가 비용은?', '없다', '스프레드(매수호가-매도호가 차이), 괴리율, 운용보수(TER)', '배당세만', '환매 수수료', 1, 'ETF 매매 시 증권사 수수료 외에도 매수·매도 호가 스프레드, 괴리율 비용, 그리고 매일 차감되는 운용보수(TER)가 발생한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 16, '13', 'ETF vs 펀드', '펀드 환매 수수료(redemption fee)의 목적은?', '운용사 수익 증대', '단기 매매를 억제하고 장기 투자자를 보호하기 위해 단기 환매 시 부과하는 비용', '기준가를 유지하기 위해', '새 투자자를 유치하기 위해', 1, '환매 수수료는 단기간(보통 3개월~1년) 내 환매 시 부과하여 장기 투자를 장려하고 빈번한 진출입으로 인한 기존 투자자 피해를 방지한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 17, '13', '괴리율', '해외 ETF에서 야간 시간대에 괴리율이 벌어지는 이유는?', '운용보수가 높기 때문', '기초자산 시장(해외 거래소)이 휴장 중이어서 현지 가격 업데이트가 안 되기 때문', '환율이 고정되기 때문', '투자자가 없기 때문', 1, '미국 S&P500 ETF를 한국 낮 시간에 거래할 때 미국 시장이 휴장 중이어서 NAV를 정확히 산출하기 어려워 괴리율이 커질 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 18, '13', 'ETF vs 펀드', '인덱스 ETF와 인덱스 펀드(뮤추얼 펀드)를 비교할 때 ETF의 유리한 점은?', '수익률이 항상 높다', '실시간 매매 가능, 일반적으로 낮은 보수, 높은 투명성', '원금 보장', '배당이 없다', 1, 'ETF는 실시간 거래, 낮은 비용, 포트폴리오 투명성 면에서 전통적 인덱스 뮤추얼 펀드보다 유리한 경우가 많다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 19, '13', '계좌 선택', '단기 트레이딩 목적의 ETF 투자 시 적합한 계좌 유형은?', 'ISA', '연금저축계좌', '일반 증권 계좌', '퇴직연금 계좌', 2, '단기 트레이딩은 수시 매매가 필요하므로 인출 제한이 없는 일반 증권 계좌가 적합하다. 연금·ISA는 장기 투자 목적에 적합하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 20, '13', '추적오차', '지수에 편입되지 않은 종목을 일부 포함하여 지수를 근사 복제하는 방식은?', '완전 복제', '샘플링(최적화 복제)', '합성 복제', '직접 복제', 1, '샘플링 방식은 지수 전체 종목 대신 대표 종목을 선별하여 지수를 근사 복제하는 방법으로 비용을 줄이지만 추적오차가 발생할 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 21, '13', 'ETF vs 펀드', '펀드 클래스 구분이 ETF에는 적용되지 않는 이유는?', 'ETF는 기관만 투자할 수 있기 때문', 'ETF는 거래소에서 단일 가격으로 거래되어 판매 채널 구분이 불필요하기 때문', 'ETF는 보수가 없기 때문', 'ETF는 펀드가 아니기 때문', 1, '일반 펀드는 판매 채널(은행, 증권사, 온라인)별로 보수 체계가 다르지만 ETF는 거래소에서 단일 시장가로 거래되어 클래스 구분이 필요 없다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 22, '13', '괴리율', 'AP(공인참가자)의 재정거래가 괴리율을 줄이는 원리는?', '정부가 가격을 조정하기 때문', 'ETF가 NAV 대비 비싸면 AP가 매도, 싸면 매수하여 가격 차이를 좁힌다', '중앙은행이 개입하기 때문', '투자자들이 자동으로 매매하기 때문', 1, 'AP는 ETF 시장가격이 NAV보다 높으면 기초자산을 사서 ETF를 설정해 팔고, 낮으면 ETF를 사서 환매해 기초자산을 팔아 괴리율을 줄이는 재정거래를 수행한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 23, '13', 'ETF vs 펀드', '개인투자자가 ETF로 글로벌 분산투자 시 이점은?', '원금 보장이 된다', '소액으로 국가·자산·섹터 다양화가 가능하고 실시간 매매로 유연성이 높다', '세금이 완전히 면제된다', '수익이 보장된다', 1, 'ETF 1좌만 매수해도 S&P500, MSCI World 등 수백 종목에 분산투자 효과를 얻을 수 있어 개인투자자에게 효율적인 글로벌 분산 수단이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 24, '13', '추적오차', '배당금 재투자 정책이 추적오차에 미치는 영향은?', '영향이 없다', '지수는 배당 재투자를 즉시 반영하지만 ETF는 배당 수령·재투자 시차로 추적오차가 발생할 수 있다', '배당이 클수록 추적오차가 줄어든다', '추적오차와 배당은 무관하다', 1, '지수(특히 총수익지수)는 배당이 지급 즉시 재투자됨을 가정하지만 실제 ETF는 배당 수령 후 재투자까지 시차가 발생하여 추적오차가 생길 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 25, '13', 'ETF vs 펀드', '헤지펀드와 일반 공모펀드의 주요 차이는?', '동일하다', '헤지펀드는 규제가 적고 공매도·레버리지 등 다양한 전략을 사용하며 주로 전문투자자 대상', '헤지펀드는 소액투자자만 참여 가능', '헤지펀드는 ETF의 일종', 1, '헤지펀드는 전문투자자(기관, 고액자산가)를 대상으로 공매도, 레버리지, 다양한 파생전략을 활용하며 규제가 공모펀드보다 덜 엄격하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 26, '13', '계좌 선택', '절세 목적으로 국내 주식형 ETF를 장기 보유할 때 가장 유리한 계좌는?', '일반 계좌', '연금저축+IRP 합산 활용', '해외 증권 계좌', '파생상품 계좌', 1, '연금저축과 IRP를 활용하면 세액공제를 받고 운용 수익에 대한 과세를 이연할 수 있어 장기 절세 투자에 가장 유리하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 27, '13', 'ETF vs 펀드', '테마형 ETF 투자 시 주의사항은?', '수익률이 보장됨', '테마 인기가 사그라들거나 고점에 상장될 경우 높은 변동성과 손실 위험', '원금 보장', '세금이 없다', 1, '테마형 ETF는 유행 테마가 고점일 때 출시되는 경우가 많고, 테마 둔화 시 큰 손실 가능성이 있어 투자 타이밍과 테마 지속성을 신중히 판단해야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 28, '13', '괴리율', '괴리율과 추적오차의 차이는?', '동일하다', '괴리율은 시장가격과 NAV 간 차이이고, 추적오차는 NAV 수익률과 기초지수 수익률 간 차이이다', '추적오차가 항상 크다', '괴리율은 관리할 수 없다', 1, '괴리율은 시장에서 형성되는 ETF 가격과 NAV의 차이(유동성 관련), 추적오차는 펀드 운용 과정에서 발생하는 지수 복제 오차이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 29, '13', 'ETF vs 펀드', '국내 ETF와 국내 상장 해외 ETF의 세금 처리 차이는?', '동일하다', '국내 주식형 ETF는 매매 차익 비과세(증권거래세만), 해외 ETF는 매매 차익 배당소득세 15.4% 과세', '해외 ETF는 세금이 없다', '모두 종합과세 대상', 1, '국내 주식형 ETF의 매매 차익은 비과세이나 해외지수 추종 ETF의 매매 차익은 배당소득세(15.4%)가 과세된다(일반 계좌 기준).');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (13, 30, '13', 'ETF vs 펀드', 'ETF의 분배금(배당)이 일반 펀드 분배금과 다른 점은?', '동일하다', 'ETF 분배금은 보유 종목의 배당·이자 수취 후 투자자에게 분배되며 연 1~4회 지급이 일반적', 'ETF는 분배금이 없다', 'ETF 분배금은 원금에서 지급된다', 1, 'ETF는 보유 종목에서 수취한 배당·이자를 투자자에게 분배금으로 지급하며 국내 ETF는 보통 연 1~4회 분배한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 1, '14', 'MPT', '현대 포트폴리오 이론(MPT)에서 해리 마코위츠의 핵심 통찰은?', '수익을 최대화하면 위험도 최대가 된다', '분산투자를 통해 총 위험을 줄이면서 동일 기대수익을 달성할 수 있다', '모든 자산에 동일한 비중으로 투자해야 한다', '위험이 없는 포트폴리오를 만들 수 있다', 1, 'MPT의 핵심은 상관관계가 낮은 자산을 결합하면 개별 자산의 위험 합산보다 포트폴리오 전체 위험을 줄일 수 있다는 분산투자 원리이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 2, '14', 'MPT', '효율적 투자선(Efficient Frontier)에 있는 포트폴리오의 특징은?', '수익이 최대인 포트폴리오들', '동일한 위험 수준에서 최대 기대수익, 또는 동일한 기대수익에서 최소 위험인 포트폴리오들', '모든 자산을 포함한 포트폴리오', '무위험 자산만 포함한 포트폴리오', 1, '효율적 투자선은 주어진 위험 수준에서 달성 가능한 최대 기대수익을 제공하는 포트폴리오들의 집합이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 3, '14', 'CAGR', 'CAGR(연평균 복합 성장률)의 계산식은?', '(최종가치 - 초기가치) / 투자기간', '(최종가치 / 초기가치)^(1/투자기간) - 1', '초기가치 × (1 + 연이율)^n', '(최종가치 / 초기가치 - 1) × 투자기간', 1, 'CAGR = (최종가치 / 초기가치)^(1/n) - 1로 투자 기간 동안 매년 일정하게 성장했다고 가정한 등가 연평균 성장률이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 4, '14', 'CAGR', 'CAGR이 단순 평균 수익률보다 더 의미 있는 성과 지표인 이유는?', '계산이 더 간단하기 때문', '변동성 효과를 고려한 복리 기준의 실질 연수익률을 나타내기 때문', '세금이 포함되기 때문', '단기 수익률을 잘 반영하기 때문', 1, 'CAGR은 투자 기간 동안 복리로 얼마나 성장했는지를 나타내어 연도별 수익률이 달라도 일관된 비교 기준을 제공한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 5, '14', 'MDD', 'MDD(Maximum Drawdown, 최대낙폭)란?', '투자 기간 중 최대 수익률', '특정 기간 내 고점 대비 최대 하락 폭', '변동성 지표', '최소 수익 달성 기간', 1, 'MDD = (저점 - 직전 고점) / 직전 고점으로 투자 기간 중 발생한 고점에서 저점까지의 최대 하락률이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 6, '14', 'MDD', 'MDD가 50%이면 원금을 회복하기 위해 필요한 수익률은?', '50%', '100%', '150%', '200%', 1, '50% 손실 후 원금 회복을 위해서는 남은 자산의 100% 수익이 필요하다. 손실과 회복에 필요한 수익률은 비대칭적이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 7, '14', '샤프비율', '샤프비율(Sharpe Ratio)의 계산식은?', '(포트폴리오 수익률 - 무위험수익률) / 포트폴리오 표준편차', '포트폴리오 수익률 / MDD', '초과수익률 / 하방 표준편차', 'CAGR / |MDD|', 0, '샤프비율 = (Rp - Rf) / σp × √252로 무위험수익률을 초과하는 수익을 전체 변동성(표준편차)으로 나눈 위험 조정 수익률이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 8, '14', '샤프비율', '샤프비율에서 √252를 곱하는 이유는?', '월간 수익률을 연간화하기 위해', '일별 수익률을 연간화하기 위해 (1년 거래일 약 252일)', '표준편차를 조정하기 위해', '무위험수익률을 반영하기 위해', 1, '일별 초과수익률과 일별 표준편차로 계산한 샤프비율을 연간 기준으로 환산하기 위해 √252(연간 거래일)를 곱한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 9, '14', '소르티노비율', '소르티노비율(Sortino Ratio)이 샤프비율과 다른 점은?', '동일하다', '분모에 전체 변동성 대신 하방 변동성(하락 표준편차)만을 사용한다', '분자가 다르다', '연간화하지 않는다', 1, '소르티노비율 = (Rp - Rf) / σ_downside × √252로 투자자에게 실질적으로 불이익인 하락 변동성만을 리스크로 계산하는 개선된 위험 조정 수익률이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 10, '14', '칼마비율', '칼마비율(Calmar Ratio)의 계산식은?', '샤프비율 / MDD', 'CAGR / |MDD|', '수익률 / 표준편차', '초과수익률 / 하방변동성', 1, '칼마비율 = CAGR / |MDD|로 단위 최대낙폭당 연평균 복합 성장률을 나타내며 특히 MDD 관리가 중요한 투자 전략 평가에 활용된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 11, '14', 'MPT', '두 자산의 상관계수가 -1에 가까울수록 포트폴리오 분산효과는?', '감소한다', '변화 없다', '최대화된다', '불확실하다', 2, '상관계수 -1은 두 자산이 완전히 반대로 움직여 포트폴리오의 분산 효과가 최대가 된다. 이론적으로 변동성을 0에 가깝게 낮출 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 12, '14', '변동성', '포트폴리오의 변동성(표준편차)이 의미하는 것은?', '항상 손실이 발생한다는 뜻', '수익률이 평균에서 얼마나 분산되어 있는지, 즉 불확실성의 크기', '수익률이 마이너스이다', 'CAGR이 낮다', 1, '변동성(표준편차)은 수익률의 불확실성을 측정하는 지표로 높을수록 수익이 크게 오르거나 내릴 수 있다는 의미이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 13, '14', '샤프비율', '샤프비율이 1 이상이면 일반적으로 어떻게 평가되는가?', '나쁜 투자', '양호한 위험 조정 수익률', '수익이 0이다', '변동성이 극대화되었다', 1, '샤프비율 1 이상이면 단위 위험당 기대수익이 양호한 수준으로 평가되며, 2 이상은 매우 우수, 3 이상은 탁월한 수준으로 간주된다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 14, '14', 'MPT', '포트폴리오 분산 투자로 줄일 수 있는 위험은?', '시장 전체 위험(베타)', '비체계적 위험(개별 자산 고유 위험)', '금리 위험', '유동성 위험', 1, '분산투자로 줄일 수 있는 것은 개별 기업이나 섹터에 특유한 비체계적 위험(unsystematic risk)이며, 시장 전체에 영향을 주는 체계적 위험(systematic risk)은 분산으로 제거 불가하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 15, '14', '효율적투자선', '최소분산 포트폴리오(MVP)란?', '수익률이 가장 높은 포트폴리오', '효율적 투자선에서 변동성이 가장 낮은 포트폴리오', '샤프비율이 가장 높은 포트폴리오', '무위험 자산으로만 구성된 포트폴리오', 1, 'MVP(Minimum Variance Portfolio)는 효율적 투자선의 가장 왼쪽 끝 점으로 주어진 자산 세계에서 분산이 가장 낮은 포트폴리오이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 16, '14', '효율적투자선', '최대 샤프비율 포트폴리오(Tangency Portfolio)의 의미는?', '변동성이 0인 포트폴리오', '자본배분선(CAL)이 효율적 투자선과 접하는 점으로 단위 위험당 수익이 최대인 포트폴리오', '수익률 최대 포트폴리오', '무위험 자산만 포함', 1, '접선 포트폴리오(Tangency Portfolio)는 무위험 자산과 결합할 때 가장 높은 샤프비율을 달성하는 위험 자산 포트폴리오이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 17, '14', 'MDD', '포트폴리오 MDD를 줄이기 위한 방법은?', '고변동성 자산만 보유', '낮은 상관관계 자산 분산 투자, 손절 전략 적용', '레버리지 극대화', '단일 섹터 집중 투자', 1, 'MDD를 줄이려면 다양한 자산에 분산 투자하여 한 자산의 급락 시 다른 자산이 완충 역할을 하거나 손절 기준을 설정하는 방법이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 18, '14', '소르티노비율', '소르티노비율이 샤프비율보다 우수한 투자 전략 평가 상황은?', '업사이드 변동성이 크지만 하락 리스크는 낮은 전략 평가 시', '변동성이 없는 전략 평가 시', '단기 전략 평가 시', '레버리지 전략 평가 시', 0, '상승 시 변동성은 투자자에게 유리하므로 하락 변동성만을 리스크로 보는 소르티노비율이 업사이드 변동성이 큰 전략을 더 정확하게 평가한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 19, '14', 'CAGR', '10년간 투자하여 초기 자산 1억원이 2억원이 되었을 때 CAGR은?', '10%', '7.2%', '5%', '20%', 1, 'CAGR = (2억/1억)^(1/10) - 1 = 2^0.1 - 1 ≈ 0.0718 ≈ 7.2%이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 20, '14', 'MPT', '상관계수가 1에 가까운 두 자산을 포트폴리오에 포함하면?', '분산 효과가 최대', '분산 효과가 거의 없어 단일 자산과 유사한 위험', '변동성이 0에 가까워진다', '수익이 2배가 된다', 1, '상관계수 +1은 두 자산이 완전히 같은 방향으로 움직여 분산 효과가 없다. 단순히 자산 수를 늘려도 상관관계가 높으면 위험 감소 효과가 미미하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 21, '14', '변동성', '연 수익률의 표준편차가 20%인 포트폴리오의 의미는?', '매년 20% 손실이 발생한다', '수익률이 평균의 약 ±20% 범위 내에 있을 가능성이 약 68%(1표준편차 기준)이다', '매년 20% 수익이 발생한다', '변동이 없다', 1, '정규분포 가정 시 1 표준편차 범위인 평균 ±20% 내에 연 수익률이 떨어질 확률이 약 68%이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 22, '14', '샤프비율', '두 포트폴리오 A(수익률 12%, 변동성 10%)와 B(수익률 18%, 변동성 20%)의 샤프비율 비교 시 (무위험수익률 2%)는?', 'A=1.0, B=0.8로 A가 우수', 'B가 절대 수익이 높아 항상 우수', '동일하다', 'B=0.8, A=1.0은 같다', 0, 'A의 샤프 = (12-2)/10 = 1.0, B의 샤프 = (18-2)/20 = 0.8로 A가 단위 위험당 수익이 더 높아 위험 조정 수익률이 우수하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 23, '14', 'MDD', 'MDD 회복 기간(Recovery Period)이 긴 투자 전략의 문제점은?', '수익률이 높다는 뜻이다', '투자자가 오랜 기간 손실 구간에 머물러 심리적으로 투자를 포기할 수 있다', 'MDD가 낮다는 의미이다', '배당이 없다는 의미이다', 1, 'MDD 회복 기간이 길면 투자자가 원금 회복 전에 투자를 중단하거나 패닉 셀링할 가능성이 높아 전략 실행의 어려움이 생긴다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 24, '14', 'MPT', '자본배분선(CAL: Capital Allocation Line)이란?', '모든 효율적 포트폴리오', '무위험 자산과 위험 포트폴리오를 혼합한 포트폴리오들의 집합', '주식만 포함한 선', 'MDD와 샤프비율의 관계선', 1, 'CAL은 무위험 자산과 특정 위험 포트폴리오를 다양한 비율로 결합할 때 가능한 위험-수익 조합을 나타내는 선이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 25, '14', '효율적투자선', '효율적 투자선 아래에 있는 포트폴리오의 특징은?', '최적 포트폴리오이다', '동일 위험에서 더 높은 수익이 가능하므로 비효율적 포트폴리오이다', '수익이 가장 높다', '변동성이 없다', 1, '효율적 투자선 아래의 포트폴리오는 같은 위험 수준에서 더 높은 수익을 얻을 수 있는 포트폴리오가 존재하므로 비효율적이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 26, '14', 'CAGR', 'CAGR의 한계점은?', '계산이 어렵다', '투자 기간 중 변동성(중간 과정의 부침)을 반영하지 못한다', '세금을 포함하지 않는다', '분기 수익률에만 사용된다', 1, 'CAGR은 시작과 끝 시점만 반영하므로 중간에 큰 폭의 등락이 있어도 최종 수치가 같으면 동일한 CAGR로 계산되어 경로 위험이 감추어진다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 27, '14', '소르티노비율', '하방 변동성(Downside Deviation)이란?', '모든 수익률의 표준편차', '목표 수익률(보통 0 또는 무위험수익률) 미만의 수익률만 사용하여 계산한 표준편차', '최대 손실', 'MDD의 다른 표현', 1, '하방 변동성은 특정 기준치(목표 수익률)를 하회하는 수익률의 표준편차로 투자자에게 불리한 하락 위험만을 측정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 28, '14', 'MPT', 'MPT의 주요 비판으로 가장 많이 언급되는 것은?', '계산이 너무 단순하다', '수익률 정규분포 가정과 공분산 추정 오차로 극단적 시장 상황을 과소평가한다', '분산투자가 불필요하다', '무위험 자산을 포함하지 않는다', 1, 'MPT는 수익률이 정규분포를 따른다고 가정하지만 실제 시장은 팻테일(fat tail) 현상이 있고 공분산 추정 오차가 포트폴리오 구성에 큰 영향을 준다는 한계가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 29, '14', '칼마비율', '칼마비율이 높은 포트폴리오의 특징은?', '변동성이 극도로 높다', '수익(CAGR) 대비 최대낙폭이 작아 안정적으로 수익을 창출한다', 'MDD가 크다', '수익률이 낮다', 1, '칼마비율 = CAGR/|MDD|로 높을수록 큰 손실 없이 꾸준한 수익을 달성하는 전략이어서 자산관리 전략 비교에 유용하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (14, 30, '14', 'MPT', '포트폴리오 최적화에서 입력 변수(기대수익률, 분산, 공분산)의 추정 오차가 중요한 이유는?', '계산이 복잡해지기 때문', '작은 입력 오차도 최적 포트폴리오 비중을 크게 변화시킬 수 있어 결과의 안정성에 영향을 준다', '비용이 증가하기 때문', '세금이 달라지기 때문', 1, 'MPT 최적화는 입력 변수에 매우 민감하여 기대수익률·공분산 추정 오류가 작아도 최적 비중이 극단적으로 달라질 수 있어 실무적 한계가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 1, '15', '자산배분', '자산배분이 포트폴리오 성과의 몇 %를 결정한다고 알려져 있는가?', '약 40%', '약 60%', '약 90% 이상', '약 30%', 2, 'Brinson et al.(1986)의 연구에 따르면 포트폴리오 성과의 90% 이상이 자산배분(주식/채권/현금 비중 결정)에 의해 결정된다고 알려져 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 2, '15', '자산배분', '마코위츠가 말한 "유일한 공짜 점심(free lunch)"이란?', '무위험 수익을 얻는 것', '분산투자를 통해 수익 포기 없이 위험을 줄일 수 있다는 것', '고수익 자산에 집중 투자', '레버리지 사용', 1, '마코위츠는 상관관계가 낮은 자산들을 결합하면 개별 자산 합산보다 위험을 줄이면서 수익을 유지할 수 있는 분산투자를 "투자에서 유일한 공짜 점심"이라고 했다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 3, '15', '자산배분', '50% 손실 후 원금 회복을 위해 필요한 수익률은?', '50%', '75%', '100%', '150%', 2, '50% 손실로 자산이 반으로 줄면 원금 회복을 위해 남은 자산의 100% 수익이 필요하다. 이 비대칭성이 MDD 관리의 중요성을 보여준다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 4, '15', 'MVO', 'MVO(Mean-Variance Optimization, 평균-분산 최적화)의 목적은?', '수익률 극대화만 추구', '주어진 기대수익률에서 분산(위험)을 최소화하거나 주어진 위험에서 기대수익을 최대화하는 포트폴리오 비중 도출', '단일 자산에 집중', '무위험 수익 확보', 1, 'MVO는 마코위츠의 효율적 투자선 도출을 위한 최적화 방법으로 입력 변수(기대수익률, 분산, 공분산)를 이용해 효율적 포트폴리오 비중을 계산한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 5, '15', 'MVO', 'MVO의 주요 실무적 한계점은?', '계산이 불가하다', '기대수익률 추정 오차에 매우 민감하여 입력값이 조금만 달라져도 결과가 크게 달라진다', '항상 낮은 수익률을 제공한다', '분산 효과가 없다', 1, 'MVO는 기대수익률 추정에 매우 민감하여 작은 추정 오차도 포트폴리오 비중을 극단적으로 변화시키는 "garbage in, garbage out" 문제가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 6, '15', '블랙-리터만', '블랙-리터만(Black-Litterman) 모델의 핵심은?', '과거 수익률만 사용', '시장 균형 수익률(역최적화)을 출발점으로 하고 투자자의 전망(view)을 베이지안 방식으로 결합한다', '등가중 포트폴리오 구성', '레버리지를 최대화한다', 1, '블랙-리터만은 시장 포트폴리오에서 역으로 추론한 균형 기대수익률에 투자자의 주관적 전망을 결합하여 더 안정적인 포트폴리오를 도출하는 모델이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 7, '15', '블랙-리터만', '블랙-리터만 모델에서 "역최적화(reverse optimization)"란?', '포트폴리오 비중을 역으로 분산시키는 것', '시장 포트폴리오 비중과 공분산 행렬로부터 시장이 내포하는 균형 기대수익률을 역산하는 것', '손실을 최대화하는 방법', '레버리지를 줄이는 방법', 1, '역최적화는 시장 포트폴리오 비중이 효율적이라고 가정하고 공분산 행렬과 함께 시장이 암묵적으로 가정하는 기대수익률을 역으로 계산하는 방법이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 8, '15', 'Risk-Parity', '리스크 패리티(Risk Parity) 전략의 핵심 원칙은?', '모든 자산에 동일 금액 투자', '각 자산이 포트폴리오 전체 위험에 동등하게 기여하도록 비중을 설정', '가장 수익이 높은 자산에 집중', '채권에만 투자', 1, '리스크 패리티는 자산별 위험 기여도를 균등화하는 전략으로 변동성이 낮은 자산(채권)에는 더 높은 비중을, 변동성이 높은 자산(주식)에는 더 낮은 비중을 부여한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 9, '15', 'Risk-Parity', '리스크 패리티 포트폴리오가 60/40 포트폴리오와 다른 점은?', '동일하다', '60/40은 금액 기준 배분이고 리스크 패리티는 위험 기여도 기준으로 각 자산의 비중을 결정한다', '리스크 패리티는 주식에 더 많이 투자한다', '60/40은 채권 비중이 낮다', 1, '60/40은 자본의 60%를 주식, 40%를 채권에 배분하지만 주식의 변동성이 채권보다 훨씬 높아 포트폴리오 위험의 90% 이상이 주식에서 나온다. 리스크 패리티는 이를 균형화한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 10, '15', '역변동성', '역변동성(Inverse Volatility) 전략이란?', '변동성이 높은 자산에 더 많이 투자', '각 자산의 변동성에 반비례하여 비중을 배분하는 방법', '변동성을 무시하고 균등 배분', '레버리지를 최대화하는 방법', 1, '역변동성 전략은 각 자산의 변동성(표준편차) 역수에 비례하여 비중을 설정하여 변동성이 낮은 자산에 더 높은 비중을 부여하는 간단한 리스크 패리티 접근법이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 11, '15', '60/40', '전통적 60/40 포트폴리오(주식 60%+채권 40%)의 채권 역할은?', '수익 극대화', '주식 하락 시 방어막(hedge) 역할과 안정적인 이자 수익 제공', '레버리지 제공', '환율 헤지', 1, '60/40에서 채권은 주식과 낮은 상관관계(또는 음의 상관관계)를 가지므로 주식 폭락 시 자산 가치가 유지되거나 상승하여 포트폴리오를 방어하는 역할을 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 12, '15', '60/40', '금리 상승 환경에서 60/40 포트폴리오의 취약점은?', '주식이 하락하기 때문', '주식과 채권이 동시에 하락하여 분산 효과가 사라질 수 있다', '변동성이 없어진다', '수익이 극대화된다', 1, '인플레이션+금리 상승 환경에서는 주식(멀티플 하락)과 채권(가격 하락) 모두 손실이 발생할 수 있어 60/40의 분산 효과가 크게 약화된다(예: 2022년).');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 13, '15', '올웨더', '레이 달리오의 올웨더(All Weather) 포트폴리오의 설계 원칙은?', '주식에 100% 투자', '어떤 경기 환경에서도 안정적으로 작동하도록 성장/침체/인플레이션/디플레이션 4가지 국면에 대응하는 자산 배분', '금만 보유', '채권 100%', 1, '올웨더는 경제 성장(+/-) × 인플레이션(+/-) 4개 조합 각각에서 잘 작동하는 자산군을 균형 있게 배분하는 리스크 패리티 기반 전략이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 14, '15', '올웨더', '올웨더 포트폴리오의 대략적인 자산 배분은?', '주식 60%, 채권 40%', '주식 30%, 장기채 40%, 중기채 15%, 금 7.5%, 원자재 7.5%', '주식 100%', '금 50%, 현금 50%', 1, '올웨더의 기본 배분은 주식 30%, 장기채권 40%, 중기채권 15%, 금 7.5%, 원자재 7.5%로 위험 기여도 균형을 고려한 구성이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 15, '15', '영구포트폴리오', '해리 브라운의 영구포트폴리오(Permanent Portfolio) 구성은?', '주식 100%', '주식 25%, 채권 25%, 금 25%, 현금 25%의 4등분 구성', '주식 50%, 채권 50%', '채권 100%', 1, '영구포트폴리오는 성장(주식), 디플레이션(채권), 인플레이션(금), 불황(현금) 환경 각각에 25%씩 배분하여 어떤 환경에서도 일부가 잘 작동하도록 설계된 정적 자산배분이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 16, '15', 'MVO', 'MVO에서 최소분산 포트폴리오(MVP)와 최대샤프 포트폴리오의 차이는?', '동일하다', 'MVP는 변동성 최소화가 목적이고, 최대샤프는 위험 대비 수익을 최대화하는 것이 목적', '최대샤프가 항상 더 낮은 수익', '둘 다 변동성이 0이다', 1, 'MVP는 효율적 투자선의 가장 왼쪽(최소 위험)이고, 최대샤프 포트폴리오는 무위험 자산과 결합 시 샤프비율이 최대가 되는 접선 포트폴리오이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 17, '15', '자산배분', '동적 자산배분(Dynamic Asset Allocation)과 정적 자산배분(Static Asset Allocation)의 차이는?', '동일하다', '정적은 최초 비중을 유지하고, 동적은 시장 상황이나 신호에 따라 비중을 조정한다', '동적 배분은 수익이 항상 높다', '정적 배분은 리밸런싱이 없다', 1, '정적 자산배분은 목표 비중을 정해 유지(주기적 리밸런싱)하고, 동적 자산배분은 경기지표, 모멘텀 등에 따라 적극적으로 비중을 조정한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 18, '15', '리밸런싱', '포트폴리오 리밸런싱(Rebalancing)의 목적은?', '수익률 극대화', '자산 가격 변동으로 목표 비중에서 벗어난 포트폴리오를 원래 목표 비중으로 되돌리는 것', '비용 절감', '세금 최소화', 1, '리밸런싱은 자산 가격이 변해 비중이 달라진 포트폴리오를 목표 비중으로 조정하여 위험 수준을 유지하고 고점에서 팔고 저점에서 사는 효과가 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 19, '15', '자산배분', '전략적 자산배분(SAA)과 전술적 자산배분(TAA)의 차이는?', '동일하다', 'SAA는 장기 목표 비중 결정이고, TAA는 단기 시장 기회를 활용하기 위해 SAA 비중에서 소폭 이탈하는 것', 'SAA가 더 적극적이다', 'TAA는 장기 투자에만 사용', 1, 'SAA는 투자자의 장기 목표에 맞는 기준 비중을 설정하고, TAA는 단기 시장 전망에 따라 SAA 비중에서 일정 범위 내 이탈하여 초과 수익을 추구한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 20, '15', 'Risk-Parity', '리스크 패리티에서 채권 비중이 일반적으로 높은 이유는?', '채권 수익이 높기 때문', '채권 변동성이 주식보다 낮아 위험 기여도를 균등화하려면 채권을 더 많이 보유해야 하기 때문', '규제 때문에', '채권이 더 유동성이 높기 때문', 1, '리스크 패리티는 각 자산의 위험 기여도를 균등화하는 전략이므로 변동성이 낮은 채권에 더 높은 비중을 부여해야 주식과 같은 수준의 위험을 기여한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 21, '15', '블랙-리터만', '블랙-리터만 모델에서 투자자 전망(view)의 신뢰도를 나타내는 파라미터는?', '기대수익률', '오메가(Ω) 행렬 - 투자자 전망의 불확실성(공분산)', 'WACC', '샤프비율', 1, '블랙-리터만에서 Ω(오메가)는 투자자 전망의 오차 공분산 행렬로 값이 작을수록 전망에 대한 확신이 높음을 나타낸다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 22, '15', '올웨더', '올웨더 포트폴리오에서 원자재가 포함된 이유는?', '수익이 가장 높기 때문', '인플레이션 상승 환경에서 원자재 가격이 오르는 경향이 있어 인플레이션 헤지 역할을 하기 때문', '변동성이 낮기 때문', '채권과 상관관계가 높기 때문', 1, '올웨더에서 원자재(상품)는 인플레이션 상승 환경에서 다른 자산들이 고전할 때 가치가 오르는 경향이 있어 포트폴리오 내 인플레이션 방어 역할을 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 23, '15', '자산배분', '자산배분에서 상관관계 행렬(Correlation Matrix)이 중요한 이유는?', '수익률 계산에만 쓰인다', '자산 간 상관관계가 포트폴리오 분산 효과를 결정하기 때문', '세금 계산에 필요하다', '단순히 시각화 도구이다', 1, '상관관계 행렬은 자산 간 동조화 정도를 나타내며 낮은 상관관계 조합이 분산 효과를 극대화하므로 효율적 포트폴리오 구성의 핵심 입력값이다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 24, '15', 'MVO', 'MVO 최적화에서 "모서리해(corner solution)" 문제란?', '최적 포트폴리오가 존재하지 않는 것', '특정 자산의 비중이 0% 또는 100%로 극단적으로 쏠리는 문제', '변동성이 0인 포트폴리오', '계산 오류', 1, 'MVO는 특정 입력 조합에서 몇 개의 자산에만 극단적으로 집중 배분하는 코너 해를 도출하는 경향이 있어 실무적 적용에 제약이 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 25, '15', 'Risk-Parity', '리스크 패리티 포트폴리오의 실무 구현 시 레버리지가 필요한 이유는?', '수익을 극대화하기 위해', '채권 비중을 크게 가져가면 전체 기대수익률이 낮아지므로 채권에 레버리지를 적용하여 목표 수익률을 달성하기 위해', '규제 준수를 위해', '세금 절감을 위해', 1, '리스크 패리티는 채권 비중이 매우 높아 기대수익률이 낮으므로 채권 포지션에 레버리지를 적용하여 전체 포트폴리오 기대수익률을 높이는 전략이 많다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 26, '15', '자산배분', '글로벌 자산배분에서 환 헤지(currency hedge) 여부가 중요한 이유는?', '세금에만 영향을 준다', '해외 자산의 환율 변동이 원화 수익률에 추가적인 수익이나 손실을 발생시키기 때문', '거래비용에만 영향을 준다', '성과 측정에 불필요하다', 1, '해외 자산 투자 시 자산 자체의 수익 외에 환율 변동(원화 강약세)이 추가 수익 또는 손실을 가져오므로 환 헤지 여부가 전략의 실질 수익률에 중요하다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 27, '15', '올웨더', '올웨더 포트폴리오에서 금(Gold)이 포함된 이유는?', '수익이 가장 높기 때문', '인플레이션과 통화 불안, 지정학적 위험 환경에서 가치 보전 역할을 하기 때문', '변동성이 낮기 때문', '이자를 지급하기 때문', 1, '금은 인플레이션 헤지 자산으로 달러 약세, 인플레이션 상승, 지정학적 불안 시기에 다른 자산과 낮은 상관관계를 유지하며 가치 저장 역할을 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 28, '15', '자산배분', '자산배분 전략 선택 시 투자자 관점에서 가장 중요한 고려 요소는?', '단기 수익 극대화만', '투자 목표, 투자 기간, 위험 허용 범위, 유동성 필요에 맞는 전략 선택', '유행하는 전략 따르기', '레버리지 극대화', 1, '자산배분 전략은 투자자의 목표(자산 증식/보전), 기간(단기/장기), 리스크 허용도, 현금 필요 시기 등 개인 상황에 맞게 설계되어야 한다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 29, '15', 'Risk-Parity', '리스크 패리티 전략이 상관관계 급변 시(위기 구간) 취약한 이유는?', '레버리지가 없기 때문', '평상시 낮은 상관관계 자산들이 위기 시 상관관계가 1로 급등하여 분산 효과가 사라지기 때문', '채권이 없기 때문', '수익률 목표가 높기 때문', 1, '금융위기 등 극단적 상황에서는 평소 낮은 상관관계를 유지하던 자산들이 동시에 급락하는 상관관계 수렴 현상이 발생하여 리스크 패리티 포트폴리오도 큰 손실을 입을 수 있다.');
INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES (15, 30, '15', '자산배분', '자산배분 전략의 장기적 성과 개선을 위해 가장 중요한 실행 원칙은?', '매일 포트폴리오 재조정', '목표 전략을 정하고 시장 변동에 흔들리지 않으며 꾸준히 유지 및 주기적 리밸런싱', '단기 수익이 날 때만 투자', '한 자산이 오르면 모두 팔기', 1, '자산배분 전략의 핵심은 시장 타이밍 시도보다 명확한 목표 비중을 설정하고 장기적으로 규율 있게 유지하며 목표 비중에서 벗어날 때 리밸런싱하는 것이다.');
